{
  "name": "تطبيق التطوير (Level Up Life)",
  "description": "A gamified life management system with daily tasks, XP, Energy, and AI coaching. Built with a mobile-first Dark/Red aesthetic."
}

export type PillarType = 'Learning' | 'Studying' | 'Exercise' | 'Work' | 'Entertainment';

export interface Task {
  id: string;
  title: string;
  description: string;
  pillar: PillarType;
  completed: boolean;
  energyCost: number;
  xpReward: number;
  dueDate?: string;
  createdAt: number;
}

export interface UserStats {
  level: number;
  currentXp: number;
  maxXp: number;
  energy: number;
  maxEnergy: number;
  streak: number;
  lastLoginDate: string; // ISO Date string YYYY-MM-DD
}

export interface GameState {
  stats: UserStats;
  tasks: Task[];
}

export const LEVEL_SCALING_FACTOR = 1.5;
export const BASE_XP_PER_LEVEL = 100;

export enum AppTab {
  DASHBOARD = 'DASHBOARD',
  PILLARS = 'PILLARS',
  COACH = 'COACH'
}

import { BookOpen, Brain, Dumbbell, Briefcase, Gamepad2, LucideIcon } from 'lucide-react';
import { PillarType } from './types';

export const PILLARS: { id: PillarType; label: string; icon: LucideIcon; color: string }[] = [
  { id: 'Learning', label: 'التعلم', icon: BookOpen, color: 'text-blue-500' },
  { id: 'Studying', label: 'الدراسة', icon: Brain, color: 'text-purple-500' },
  { id: 'Exercise', label: 'الرياضة', icon: Dumbbell, color: 'text-green-500' },
  { id: 'Work', label: 'العمل', icon: Briefcase, color: 'text-orange-500' },
  { id: 'Entertainment', label: 'الترفيه', icon: Gamepad2, color: 'text-pink-500' },
];

export const MAX_DAILY_ENERGY = 100;
export const ENERGY_REGEN_PER_DAY = 100;
export const DEFAULT_TASK_COST = 10;
export const DEFAULT_TASK_XP = 25;

import { GoogleGenAI } from "@google/genai";
import { UserStats, Task } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const getCoachAdvice = async (stats: UserStats, tasks: Task[]): Promise<string> => {
  const ai = getClient();
  if (!ai) return "الرجاء إعداد مفتاح API الخاص بـ Gemini للحصول على نصائح المدرب.";

  const pendingTasks = tasks.filter(t => !t.completed).length;
  const completedTasks = tasks.filter(t => t.completed).length;

  const prompt = `
    You are a hardcore, motivating life-coach for a gamified productivity app called "Level Up Life".
    The user's current stats are:
    - Level: ${stats.level}
    - XP: ${stats.currentXp}/${stats.maxXp}
    - Energy: ${stats.energy}/${stats.maxEnergy}
    - Streak: ${stats.streak} days
    - Tasks Pending: ${pendingTasks}
    - Tasks Completed Today: ${completedTasks}

    The theme is Red and Black, aggressive but supportive.
    Give the user a short, punchy paragraph of advice (in Arabic) on what to focus on next.
    If energy is low, tell them to rest. If streak is high, congratulate them.
    Keep it under 50 words. Use emojis suitable for a game.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: prompt,
    });
    return response.text || "استمر في التقدم يا بطل!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "المدرب في استراحة حالياً. حاول لاحقاً.";
  }
};

import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { GameState, Task, UserStats, PillarType, BASE_XP_PER_LEVEL, LEVEL_SCALING_FACTOR } from '../types';
import { MAX_DAILY_ENERGY, ENERGY_REGEN_PER_DAY } from '../constants';

interface GameContextType extends GameState {
  addTask: (title: string, description: string, pillar: PillarType, energyCost: number) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  resetProgress: () => void;
}

const defaultStats: UserStats = {
  level: 1,
  currentXp: 0,
  maxXp: BASE_XP_PER_LEVEL,
  energy: MAX_DAILY_ENERGY,
  maxEnergy: MAX_DAILY_ENERGY,
  streak: 0,
  lastLoginDate: new Date().toISOString().split('T')[0],
};

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load from Storage
  useEffect(() => {
    const savedStats = localStorage.getItem('game_stats');
    const savedTasks = localStorage.getItem('game_tasks');

    if (savedStats) setStats(JSON.parse(savedStats));
    if (savedTasks) setTasks(JSON.parse(savedTasks));

    checkDailyReset();
    setIsLoaded(true);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Save to Storage
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('game_stats', JSON.stringify(stats));
      localStorage.setItem('game_tasks', JSON.stringify(tasks));
    }
  }, [stats, tasks, isLoaded]);

  const checkDailyReset = () => {
    const today = new Date().toISOString().split('T')[0];
    setStats(prev => {
      if (prev.lastLoginDate === today) return prev;

      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);
      const yesterdayStr = yesterday.toISOString().split('T')[0];

      let newStreak = prev.streak;
      if (prev.lastLoginDate === yesterdayStr) {
        newStreak += 1;
      } else {
        newStreak = 1; // Reset streak if missed a day, or 1 if new
      }

      return {
        ...prev,
        energy: Math.min(prev.maxEnergy, prev.energy + ENERGY_REGEN_PER_DAY),
        lastLoginDate: today,
        streak: newStreak
      };
    });
  };

  const addTask = (title: string, description: string, pillar: PillarType, energyCost: number) => {
    const newTask: Task = {
      id: crypto.randomUUID(),
      title,
      description,
      pillar,
      completed: false,
      energyCost,
      xpReward: Math.floor(energyCost * 1.5), // XP is based on effort
      createdAt: Date.now(),
    };
    setTasks(prev => [...prev, newTask]);
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const completeTask = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (stats.energy < task.energyCost) {
      alert("طاقة غير كافية! خذ استراحة.");
      return;
    }

    // Update Tasks
    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: true } : t));

    // Update Stats
    setStats(prev => {
      let newXp = prev.currentXp + task.xpReward;
      let newLevel = prev.level;
      let newMaxXp = prev.maxXp;

      // Level Up Logic
      if (newXp >= newMaxXp) {
        newXp -= newMaxXp;
        newLevel += 1;
        newMaxXp = Math.floor(newMaxXp * LEVEL_SCALING_FACTOR);
      }

      return {
        ...prev,
        currentXp: newXp,
        level: newLevel,
        maxXp: newMaxXp,
        energy: prev.energy - task.energyCost,
      };
    });
  };

  const resetProgress = () => {
    if (confirm("هل أنت متأكد من إعادة تعيين كل التقدم؟")) {
      setStats(defaultStats);
      setTasks([]);
    }
  };

  return (
    <GameContext.Provider value={{ stats, tasks, addTask, deleteTask, completeTask, resetProgress }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React from 'react';

interface Props {
  current: number;
  max: number;
  colorClass: string;
  label?: string;
  height?: string;
  showText?: boolean;
}

export const ProgressBar: React.FC<Props> = ({ current, max, colorClass, label, height = 'h-4', showText = true }) => {
  const percentage = Math.min(100, Math.max(0, (current / max) * 100));

  return (
    <div className="w-full my-1">
      {label && (
        <div className="flex justify-between text-xs font-bold mb-1 uppercase tracking-widest text-neutral-400">
          <span>{label}</span>
          {showText && <span>{current} / {max}</span>}
        </div>
      )}
      <div className={`w-full bg-neutral-800 rounded-full overflow-hidden ${height} border border-neutral-700`}>
        <div
          className={`${height} ${colorClass} transition-all duration-500 ease-out`}
          style={{ width: `${percentage}%` }}
        />
      </div>
    </div>
  );
};

import React from 'react';
import { useGame } from '../context/GameContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { PILLARS } from '../constants';
import { ProgressBar } from './ProgressBar';
import { Activity, Flame, Trophy, Zap } from 'lucide-react';

export const Dashboard: React.FC = () => {
  const { stats, tasks } = useGame();

  // Calculate Tasks per Pillar
  const data = PILLARS.map(pillar => ({
    name: pillar.label,
    value: tasks.filter(t => t.pillar === pillar.id && t.completed).length,
    color: pillar.color
  })).filter(d => d.value > 0);

  // Fallback if no data
  const chartData = data.length > 0 ? data : [{ name: 'لا يوجد بيانات', value: 1, color: '#333' }];

  return (
    <div className="space-y-6 pb-20 animate-fade-in">
      {/* Header Stats */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-neutral-900 border border-game-red-dim p-4 rounded-xl shadow-lg relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                <Trophy size={48} />
            </div>
            <p className="text-neutral-400 text-sm font-bold">المستوى</p>
            <p className="text-4xl font-black text-white">{stats.level}</p>
            <div className="mt-2">
                <ProgressBar current={stats.currentXp} max={stats.maxXp} colorClass="bg-game-red" height="h-2" showText={false} />
                <p className="text-xs text-right mt-1 text-neutral-500">{stats.currentXp} / {stats.maxXp} XP</p>
            </div>
        </div>

        <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-xl shadow-lg flex flex-col justify-between">
            <div className="flex items-center justify-between mb-2">
                <span className="text-neutral-400 text-sm font-bold">الطاقة</span>
                <Zap className="text-yellow-500" size={18} />
            </div>
            <p className="text-2xl font-bold text-white mb-2">{stats.energy} <span className="text-sm text-neutral-500">/ {stats.maxEnergy}</span></p>
            <ProgressBar current={stats.energy} max={stats.maxEnergy} colorClass="bg-yellow-500" height="h-2" showText={false} />
        </div>

        <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-xl shadow-lg flex flex-col justify-between">
             <div className="flex items-center justify-between mb-2">
                <span className="text-neutral-400 text-sm font-bold">سلسلة الأيام</span>
                <Flame className="text-orange-500" size={18} />
            </div>
            <p className="text-3xl font-bold text-white">{stats.streak} <span className="text-sm font-normal text-neutral-500">أيام</span></p>
        </div>

         <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-xl shadow-lg flex flex-col justify-between">
             <div className="flex items-center justify-between mb-2">
                <span className="text-neutral-400 text-sm font-bold">المهام المنجزة</span>
                <Activity className="text-blue-500" size={18} />
            </div>
            <p className="text-3xl font-bold text-white">{tasks.filter(t => t.completed).length}</p>
        </div>
      </div>

      {/* Chart Section */}
      <div className="bg-neutral-900 border border-neutral-800 p-4 rounded-xl shadow-lg">
        <h3 className="text-lg font-bold mb-4 text-white border-b border-neutral-800 pb-2">توزيع الإنجاز</h3>
        <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
            <PieChart>
                <Pie
                    data={chartData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    stroke="none"
                >
                {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={data.length > 0 ? (entry as any).color.replace('text-', 'bg-').replace('-500', '-600') : '#333'} /> // Rudimentary color mapping
                ))}
                </Pie>
                <Tooltip 
                    contentStyle={{ backgroundColor: '#171717', border: '1px solid #333', borderRadius: '8px' }}
                    itemStyle={{ color: '#fff' }}
                />
            </PieChart>
            </ResponsiveContainer>
        </div>
        <div className="grid grid-cols-2 gap-2 mt-4">
            {data.map(d => (
                <div key={d.name} className="flex items-center text-xs text-neutral-400">
                    <div className={`w-3 h-3 rounded-full mr-2 ml-2 ${d.color.replace('text-', 'bg-')}`}></div>
                    {d.name}: {d.value}
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { getCoachAdvice } from '../services/geminiService';
import { Bot, RefreshCw } from 'lucide-react';

export const AICoach: React.FC = () => {
  const { stats, tasks } = useGame();
  const [advice, setAdvice] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const askCoach = async () => {
    setLoading(true);
    const result = await getCoachAdvice(stats, tasks);
    setAdvice(result);
    setLoading(false);
  };

  return (
    <div className="flex flex-col items-center justify-center h-full p-6 text-center space-y-6 animate-fade-in pb-20">
      <div className="w-24 h-24 bg-game-red rounded-full flex items-center justify-center shadow-[0_0_20px_rgba(220,38,38,0.5)] mb-4">
        <Bot size={48} className="text-white" />
      </div>

      <h2 className="text-2xl font-bold text-white">مدربك الذكي</h2>
      <p className="text-neutral-400 text-sm">
        يستخدم الذكاء الاصطناعي لتحليل أدائك ومستوى طاقتك لتقديم النصيحة المثالية الآن.
      </p>

      {advice && (
        <div className="bg-neutral-900 border border-game-red p-6 rounded-xl shadow-lg w-full relative">
            <div className="absolute -top-3 right-4 bg-game-black px-2 text-game-red text-xs font-bold border border-game-red rounded">نصيحة</div>
            <p className="text-lg leading-relaxed text-white font-medium">"{advice}"</p>
        </div>
      )}

      <button
        onClick={askCoach}
        disabled={loading}
        className="flex items-center space-x-2 space-x-reverse bg-white text-black px-6 py-3 rounded-full font-bold active:scale-95 transition-transform disabled:opacity-50"
      >
        {loading ? (
            <RefreshCw className="animate-spin ml-2" size={20} />
        ) : (
            <Bot className="ml-2" size={20} />
        )}
        <span>{loading ? 'جاري التحليل...' : advice ? 'اطلب نصيحة أخرى' : 'تحليل أدائي'}</span>
      </button>

        {!process.env.API_KEY && (
            <p className="text-xs text-red-500 mt-4">ملاحظة: لم يتم العثور على API_KEY. لن تعمل ميزة الذكاء الاصطناعي بشكل كامل.</p>
        )}
    </div>
  );
};

import React from 'react';
import { Task } from '../types';
import { CheckCircle2, Trash2, Zap } from 'lucide-react';
import { PILLARS } from '../constants';

interface Props {
  task: Task;
  onComplete: (id: string) => void;
  onDelete: (id: string) => void;
  canAfford: boolean;
}

export const TaskItem: React.FC<Props> = ({ task, onComplete, onDelete, canAfford }) => {
  const pillarInfo = PILLARS.find(p => p.id === task.pillar);

  return (
    <div className={`
      relative p-4 rounded-xl border border-neutral-800 bg-neutral-900 mb-3 transition-all duration-300
      ${task.completed ? 'opacity-50 grayscale' : 'hover:border-neutral-600'}
    `}>
      <div className="flex justify-between items-start">
        <div className="flex-1 ml-2">
            <div className="flex items-center gap-2 mb-1">
                {pillarInfo && <pillarInfo.icon size={14} className={pillarInfo.color} />}
                <span className={`text-[10px] px-2 py-0.5 rounded bg-neutral-800 ${pillarInfo?.color}`}>{pillarInfo?.label}</span>
            </div>
          <h4 className={`font-bold text-white ${task.completed ? 'line-through decoration-game-red' : ''}`}>
            {task.title}
          </h4>
          {task.description && <p className="text-xs text-neutral-500 mt-1">{task.description}</p>}

          <div className="flex items-center mt-3 gap-3">
             <div className="flex items-center text-xs text-yellow-500 font-mono bg-neutral-950 px-2 py-1 rounded border border-neutral-800">
                <Zap size={10} className="ml-1" /> -{task.energyCost}
             </div>
             <div className="text-xs text-game-red font-mono">+{task.xpReward} XP</div>
          </div>
        </div>

        <div className="flex flex-col gap-2">
            {!task.completed && (
                <button
                onClick={() => onComplete(task.id)}
                disabled={!canAfford}
                className={`
                    p-2 rounded-full transition-colors
                    ${canAfford 
                        ? 'bg-game-red text-white hover:bg-red-500 shadow-[0_0_10px_rgba(220,38,38,0.3)]' 
                        : 'bg-neutral-800 text-neutral-600 cursor-not-allowed'}
                `}
                >
                <CheckCircle2 size={20} />
                </button>
            )}
            <button
                onClick={() => onDelete(task.id)}
                className="p-2 text-neutral-600 hover:text-red-400 transition-colors"
            >
                <Trash2 size={18} />
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { PILLARS } from '../constants';
import { TaskItem } from './TaskItem';
import { PillarType } from '../types';
import { Plus, X } from 'lucide-react';

export const PillarsView: React.FC = () => {
  const { tasks, addTask, completeTask, deleteTask, stats } = useGame();
  const [activeTab, setActiveTab] = useState<PillarType>('Learning');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [title, setTitle] = useState('');
  const [desc, setDesc] = useState('');
  const [cost, setCost] = useState(10);

  const activePillarTasks = tasks.filter(t => t.pillar === activeTab);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title) return;
    addTask(title, desc, activeTab, cost);
    setTitle('');
    setDesc('');
    setIsModalOpen(false);
  };

  return (
    <div className="h-full flex flex-col pb-24">
      {/* Pillars Tabs */}
      <div className="flex overflow-x-auto gap-2 pb-4 no-scrollbar mb-2">
        {PILLARS.map(pillar => (
          <button
            key={pillar.id}
            onClick={() => setActiveTab(pillar.id)}
            className={`
              flex items-center space-x-2 space-x-reverse px-4 py-2 rounded-full whitespace-nowrap text-sm font-bold border transition-all
              ${activeTab === pillar.id 
                ? `bg-neutral-100 text-black border-white shadow-[0_0_15px_rgba(255,255,255,0.2)]` 
                : 'bg-neutral-900 text-neutral-400 border-neutral-800'}
            `}
          >
            <pillar.icon size={16} className={activeTab === pillar.id ? 'text-black' : pillar.color} />
            <span className="mr-2">{pillar.label}</span>
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="flex-1 overflow-y-auto pr-1">
        {activePillarTasks.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-48 text-neutral-600">
                <p>لا توجد مهام في هذا الركن</p>
                <button onClick={() => setIsModalOpen(true)} className="text-game-red text-sm mt-2 underline">أضف مهمة</button>
            </div>
        ) : (
            activePillarTasks.sort((a,b) => (a.completed === b.completed ? 0 : a.completed ? 1 : -1)).map(task => (
            <TaskItem 
                key={task.id} 
                task={task} 
                onComplete={completeTask} 
                onDelete={deleteTask}
                canAfford={stats.energy >= task.energyCost}
            />
            ))
        )}
      </div>

      {/* FAB */}
      <button 
        onClick={() => setIsModalOpen(true)}
        className="fixed bottom-24 left-6 bg-game-red text-white p-4 rounded-full shadow-[0_0_20px_rgba(220,38,38,0.6)] hover:scale-110 transition-transform z-10"
      >
        <Plus size={24} />
      </button>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
          <div className="bg-neutral-900 border border-neutral-800 w-full max-w-md rounded-2xl p-6 relative">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-4 left-4 text-neutral-500 hover:text-white">
                <X size={24} />
            </button>
            <h3 className="text-xl font-bold text-white mb-6">مهمة جديدة: {PILLARS.find(p => p.id === activeTab)?.label}</h3>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-xs text-neutral-400 mb-1">العنوان</label>
                <input 
                    type="text" 
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none"
                    placeholder="ماذا تريد أن تنجز؟"
                />
              </div>

              <div>
                <label className="block text-xs text-neutral-400 mb-1">الوصف (اختياري)</label>
                <textarea 
                    value={desc}
                    onChange={(e) => setDesc(e.target.value)}
                    className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none h-20"
                    placeholder="تفاصيل إضافية..."
                />
              </div>

              <div>
                <label className="block text-xs text-neutral-400 mb-1">تكلفة الطاقة: {cost}</label>
                <input 
                    type="range" 
                    min="5" 
                    max="50" 
                    step="5"
                    value={cost}
                    onChange={(e) => setCost(Number(e.target.value))}
                    className="w-full accent-game-red"
                />
                <div className="flex justify-between text-[10px] text-neutral-500">
                    <span>سهلة (5)</span>
                    <span>صعبة (50)</span>
                </div>
              </div>

              <button 
                type="submit" 
                className="w-full bg-white text-black font-bold py-3 rounded-xl hover:bg-neutral-200 transition-colors mt-4"
              >
                إنشاء المهمة
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { GameProvider } from './context/GameContext';
import { Dashboard } from './components/Dashboard';
import { PillarsView } from './components/PillarsView';
import { AICoach } from './components/AICoach';
