import React, { createContext, useContext, useEffect, useState } from 'react';
import { GameState, Task, UserStats, PillarType, LEVEL_SCALING_FACTOR } from '../types';
import { ENERGY_REGEN_PER_DAY } from '../constants';
import { StorageService, defaultStats } from '../services/storage';

interface GameContextType extends GameState {
  addTask: (title: string, description: string, pillar: PillarType, energyCost: number) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  resetProgress: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load from Storage
  useEffect(() => {
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();

    if (loadedStats) setStats(loadedStats);
    if (loadedTasks) setTasks(loadedTasks);

    setIsLoaded(true);
  }, []);

  // Check Daily Reset after load
  useEffect(() => {
    if (!isLoaded) return;

    const today = new Date().toISOString().split('T')[0];
    setStats(prev => {
      if (prev.lastLoginDate === today) return prev;

      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);
      const yesterdayStr = yesterday.toISOString().split('T')[0];

      let newStreak = prev.streak;
      // If last login was yesterday, increment. If today, do nothing. Else (missed a day), reset to 1.
      if (prev.lastLoginDate === yesterdayStr) {
        newStreak += 1;
      } else if (prev.lastLoginDate !== today) {
        newStreak = 1;
      }

      const updatedStats = {
        ...prev,
        energy: Math.min(prev.maxEnergy, prev.energy + ENERGY_REGEN_PER_DAY),
        lastLoginDate: today,
        streak: newStreak
      };

      // Save immediately upon update
      StorageService.saveStats(updatedStats);
      return updatedStats;
    });
  }, [isLoaded]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded]);

  const addTask = (title: string, description: string, pillar: PillarType, energyCost: number) => {
    const newTask: Task = {
      id: crypto.randomUUID(),
      title,
      description,
      pillar,
      completed: false,
      energyCost,
      xpReward: Math.floor(energyCost * 1.5),
      createdAt: Date.now(),
    };
    setTasks(prev => [...prev, newTask]);
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const completeTask = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (stats.energy < task.energyCost) {
      alert("طاقة غير كافية! خذ استراحة.");
      return;
    }

    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
      let newXp = prev.currentXp + task.xpReward;
      let newLevel = prev.level;
      let newMaxXp = prev.maxXp;

      if (newXp >= newMaxXp) {
        newXp -= newMaxXp;
        newLevel += 1;
        newMaxXp = Math.floor(newMaxXp * LEVEL_SCALING_FACTOR);
      }

      return {
        ...prev,
        currentXp: newXp,
        level: newLevel,
        maxXp: newMaxXp,
        energy: prev.energy - task.energyCost,
      };
    });
  };

  const resetProgress = () => {
    if (confirm("هل أنت متأكد من إعادة تعيين كل التقدم؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
    }
  };

  return (
    <GameContext.Provider value={{ stats, tasks, addTask, deleteTask, completeTask, resetProgress }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

