interface Props {
  pillarId: PillarType;
  taskCount: number;
  onClick?: () => void;
  variant?: 'card' | 'header'; // 'card' for Dashboard, 'header' for Screen
}

export const PillWidget: React.FC<Props> = ({ pillarId, taskCount, onClick, variant = 'card' }) => {
  const pillar = PILLARS.find(p => p.id === pillarId);
  if (!pillar) return null;

  const isCard = variant === 'card';

  return (
    <button 
      onClick={onClick}
      disabled={!onClick}
      className={`
        relative overflow-hidden group transition-all duration-300 w-full text-right
        ${isCard 
          ? 'bg-neutral-900 border border-neutral-800 p-4 rounded-xl hover:border-neutral-600 hover:scale-[1.02] shadow-lg' 
          : 'bg-neutral-950 border-b border-neutral-800 p-6 pb-8'}
      `}
    >
