import React from 'react';
import { PillarType } from '../types';
import { useGame } from '../context/GameContext';
import { PillWidget } from './PillWidget';
import { TaskItem } from './TaskItem';
import { ArrowRight, Plus } from 'lucide-react';
import { PILLARS } from '../constants';

interface Props {
  pillarId: PillarType;
  onBack: () => void;
  onAddTask: () => void;
}

export const PillarDetailScreen: React.FC<Props> = ({ pillarId, onBack, onAddTask }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();

  const pillarTasks = tasks.filter(t => t.pillar === pillarId);
  const activeTasks = pillarTasks.filter(t => !t.completed);
  const completedTasks = pillarTasks.filter(t => t.completed);

  // Sorting: Newest first
  activeTasks.sort((a, b) => b.createdAt - a.createdAt);

  return (
    <div className="flex flex-col h-full bg-game-black animate-fade-in absolute inset-0 z-30">

      {/* Header Area */}
      <div className="relative">
        <button 
            onClick={onBack}
            className="absolute top-6 left-4 z-20 p-2 bg-black/50 backdrop-blur rounded-full text-white border border-neutral-700 hover:bg-neutral-800"
        >
            <ArrowRight size={20} />
        </button>
        <PillWidget pillarId={pillarId} taskCount={activeTasks.length} variant="header" />
      </div>

      {/* Task List */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">

        {activeTasks.length === 0 && completedTasks.length === 0 && (
             <div className="flex flex-col items-center justify-center h-64 text-neutral-500 opacity-60">
                <p>لا توجد مهام نشطة</p>
                <p className="text-xs mt-2">اضغط على + لإضافة مهمة جديدة</p>
             </div>
        )}

        {/* Active Tasks */}
        {activeTasks.map(task => (
            <TaskItem 
                key={task.id}
                task={task}
                onComplete={completeTask}
                onDelete={deleteTask}
                canAfford={stats.energy >= task.energyCost}
            />
        ))}

        {/* Completed Tasks Header */}
        {completedTasks.length > 0 && (
            <div className="pt-6 border-t border-neutral-900">
                <h4 className="text-xs font-bold text-neutral-600 mb-4 uppercase tracking-widest">المكتملة</h4>
                {completedTasks.map(task => (
                    <TaskItem 
                        key={task.id}
                        task={task}
                        onComplete={completeTask}
                        onDelete={deleteTask}
                        canAfford={true}
                    />
                ))}
            </div>
        )}
      </div>

      {/* FAB to Add Task */}
      <button 
        onClick={onAddTask}
        className="fixed bottom-8 left-6 bg-white text-black p-4 rounded-full shadow-[0_0_20px_rgba(255,255,255,0.3)] hover:scale-110 transition-transform z-40"
      >
        <Plus size={24} />
      </button>
    </div>
  );
};

