const AppContent: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [currentStackScreen, setCurrentStackScreen] = useState<StackScreen>('ROOT');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const { resetProgress, addTask } = useGame();

  // Add Task Form State
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskCost, setNewTaskCost] = useState(10);

  const navigateToPillar = (pillar: PillarType) => {
    setActiveTab(AppTab.PILLARS); // Highlight pillars tab
    setCurrentStackScreen(pillar);
  };

  const handleBack = () => {
    setCurrentStackScreen('ROOT');
    setActiveTab(AppTab.DASHBOARD);
  };

  const openAddTask = () => setIsAddModalOpen(true);

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle || currentStackScreen === 'ROOT') return;

    // We know currentStackScreen is a PillarType here because ROOT is handled
    addTask(newTaskTitle, '', currentStackScreen as PillarType, newTaskCost);
    setNewTaskTitle('');
    setIsAddModalOpen(false);
  };

  const renderContent = () => {
    // If we are in a specific pillar screen (Phase 2 Stack Navigation)
    if (currentStackScreen !== 'ROOT') {
        const props = { onBack: handleBack, onAddTask: openAddTask };
        switch (currentStackScreen) {
            case 'Learning': return <LearningScreen {...props} />;
            case 'Studying': return <StudyingScreen {...props} />;
            case 'Exercise': return <ExerciseScreen {...props} />;
            case 'Work': return <WorkScreen {...props} />;
            case 'Entertainment': return <EntertainmentScreen {...props} />;
        }
    }

    // Default Tab Navigation
    switch (activeTab) {
      case AppTab.DASHBOARD: 
        return <Dashboard onNavigateToPillar={navigateToPillar} />;
      case AppTab.PILLARS: 
        // If tab is clicked directly, show the list view or reset stack? 
        // For Phase 2, let's keep the PillarsView as a "All Tasks" or "Quick Add" view, 
        // OR redirect to dashboard pillars. Let's keep existing PillarsView for now.
        return <PillarsView />;
      case AppTab.COACH: 
        return <AICoach />;
      default: 
        return <Dashboard onNavigateToPillar={navigateToPillar} />;
    }
  };

  return (
    <div className="min-h-screen bg-game-black text-white flex justify-center">
      <div className="w-full max-w-md h-screen flex flex-col relative bg-neutral-950 shadow-2xl overflow-hidden">

        {/* Header (Only show if not in stack screen) */}
        {currentStackScreen === 'ROOT' && (
            <header className="p-4 flex justify-between items-center border-b border-neutral-900 bg-game-black/50 backdrop-blur-md sticky top-0 z-20">
                <h1 className="text-xl font-black tracking-tighter text-white">
                    تطبيق <span className="text-game-red">التطوير</span>
                </h1>
                <button onClick={resetProgress} className="text-neutral-600 hover:text-red-500 transition-colors">
                    <Settings size={20} />
                </button>
            </header>
        )}

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto relative no-scrollbar">
            {renderContent()}
        </main>

        {/* Bottom Navigation (Hide in Detail Screen) */}
        {currentStackScreen === 'ROOT' && (
            <nav className="border-t border-neutral-800 bg-game-black pb-safe pt-2 px-4 absolute bottom-0 w-full z-20">
                <div className="flex justify-around items-center h-16">
                    <NavButton 
                        active={activeTab === AppTab.DASHBOARD} 
                        onClick={() => { setActiveTab(AppTab.DASHBOARD); setCurrentStackScreen('ROOT'); }} 
                        icon={LayoutDashboard} 
                        label="الرئيسية" 
                    />
                    <NavButton 
                        active={activeTab === AppTab.PILLARS} 
                        onClick={() => { setActiveTab(AppTab.PILLARS); setCurrentStackScreen('ROOT'); }} 
                        icon={ListTodo} 
                        label="المهام" 
                    />
                    <NavButton 
                        active={activeTab === AppTab.COACH} 
                        onClick={() => { setActiveTab(AppTab.COACH); setCurrentStackScreen('ROOT'); }} 
                        icon={Bot} 
                        label="المدرب" 
                    />
                </div>
            </nav>
        )}

        {/* Quick Add Task Modal */}
        {isAddModalOpen && (
            <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
              <div className="bg-neutral-900 border border-neutral-800 w-full max-w-md rounded-2xl p-6 relative">
                <button onClick={() => setIsAddModalOpen(false)} className="absolute top-4 left-4 text-neutral-500 hover:text-white">
                    <X size={24} />
                </button>
                <h3 className="text-xl font-bold text-white mb-6">
                    مهمة جديدة: {PILLARS.find(p => p.id === currentStackScreen)?.label}
                </h3>

                <form onSubmit={handleAddTask} className="space-y-4">
                  <div>
                    <label className="block text-xs text-neutral-400 mb-1">العنوان</label>
                    <input 
                        type="text" 
                        value={newTaskTitle}
                        onChange={(e) => setNewTaskTitle(e.target.value)}
                        className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none"
                        placeholder="ماذا تريد أن تنجز؟"
                        autoFocus
                    />
                  </div>

                  <div>
                    <label className="block text-xs text-neutral-400 mb-1">تكلفة الطاقة: {newTaskCost}</label>
                    <input 
                        type="range" 
                        min="5" 
                        max="50" 
                        step="5"
