export type PillarType = 'Learning' | 'Studying' | 'Exercise' | 'Work' | 'Entertainment';

export interface Task {
  id: string;
  title: string;
  description: string;
  pillar: PillarType;
  completed: boolean;
  energyCost: number;
  xpReward: number;
  dueDate?: string;
  createdAt: number;
}

export interface UserStats {
  level: number;
  currentXp: number;
  maxXp: number;
  energy: number;
  maxEnergy: number;
  streak: number;
  lastLoginDate: string; // ISO Date string YYYY-MM-DD
  lastTaskCompletionDate?: string; // Tracks streak based on task completion
}

export interface GameState {
  stats: UserStats;
  tasks: Task[];
}

export interface PillarsData {
  Learning: Task[];
  Studying: Task[];
  Exercise: Task[];
  Work: Task[];
  Entertainment: Task[];
}

export const LEVEL_SCALING_FACTOR = 1.5;
export const BASE_XP_PER_LEVEL = 100;

export enum AppTab {
  DASHBOARD = 'DASHBOARD',
  PILLARS = 'PILLARS',
  COACH = 'COACH'
}

export type StackScreen = 'ROOT' | PillarType;

import { UserStats, Task, BASE_XP_PER_LEVEL, PillarsData, PillarType } from '../types';
import { MAX_DAILY_ENERGY, PILLARS } from '../constants';

const STATS_KEY = 'game_stats';
const PILLARS_KEY = 'game_pillars'; // Updated key for Phase 2 structure

export const defaultStats: UserStats = {
  level: 1,
  currentXp: 0,
  maxXp: BASE_XP_PER_LEVEL,
  energy: MAX_DAILY_ENERGY,
  maxEnergy: MAX_DAILY_ENERGY,
  streak: 0,
  lastLoginDate: new Date().toISOString().split('T')[0],
  lastTaskCompletionDate: '',
};

const emptyPillarsData: PillarsData = {
  Learning: [],
  Studying: [],
  Exercise: [],
  Work: [],
  Entertainment: []
};

export const StorageService = {
  saveStats: (stats: UserStats) => {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(stats));
    } catch (e) {
      console.error("Failed to save stats", e);
    }
  },

  loadStats: (): UserStats | null => {
    try {
      const data = localStorage.getItem(STATS_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error("Failed to load stats", e);
      return null;
    }
  },

  // Save tasks in the requested 'pillars' object structure
  saveTasks: (tasks: Task[]) => {
    try {
      const pillarsData: PillarsData = { ...emptyPillarsData };

      // Distribute tasks into columns
      tasks.forEach(task => {
        if (pillarsData[task.pillar]) {
          pillarsData[task.pillar].push(task);
        }
      });

      localStorage.setItem(PILLARS_KEY, JSON.stringify(pillarsData));
    } catch (e) {
      console.error("Failed to save pillars", e);
    }
  },

  // Load tasks and flatten them back to an array for the app to use
  loadTasks: (): Task[] => {
    try {
      const data = localStorage.getItem(PILLARS_KEY);
      if (!data) return [];

      const pillarsData: PillarsData = JSON.parse(data);
      let allTasks: Task[] = [];

      (Object.keys(pillarsData) as PillarType[]).forEach(key => {
        if (Array.isArray(pillarsData[key])) {
          allTasks = [...allTasks, ...pillarsData[key]];
        }
      });

      return allTasks;
    } catch (e) {
      console.error("Failed to load pillars", e);
      return [];
    }
  },

  clearAll: () => {
    localStorage.removeItem(STATS_KEY);
    localStorage.removeItem(PILLARS_KEY);
  }
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { GameState, Task, UserStats, PillarType, LEVEL_SCALING_FACTOR } from '../types';
import { ENERGY_REGEN_PER_DAY } from '../constants';
import { StorageService, defaultStats } from '../services/storage';

interface GameContextType extends GameState {
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  resetProgress: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load from Storage
  useEffect(() => {
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();

    if (loadedStats) setStats(loadedStats);
    if (loadedTasks) setTasks(loadedTasks);

    setIsLoaded(true);
  }, []);

  // Check Daily Reset (Energy Only)
  useEffect(() => {
    if (!isLoaded) return;

    const today = new Date().toISOString().split('T')[0];

    setStats(prev => {
      if (prev.lastLoginDate === today) return prev; // Already updated today

      // Only regenerate energy on a new day, don't touch streak here
      const updatedStats = {
        ...prev,
        energy: Math.min(prev.maxEnergy, prev.energy + ENERGY_REGEN_PER_DAY),
        lastLoginDate: today,
      };

      StorageService.saveStats(updatedStats);
      return updatedStats;
    });
  }, [isLoaded]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded]);

  const addTask = (taskData: Partial<Task>) => {
    const newTask: Task = {
      id: crypto.randomUUID(),
      title: taskData.title || 'مهمة جديدة',
      description: taskData.description || '',
      pillar: taskData.pillar || 'Work',
      completed: false,
      energyCost: taskData.energyCost || 10,
      xpReward: taskData.xpReward || Math.floor((taskData.energyCost || 10) * 1.5),
      dueDate: taskData.dueDate,
      createdAt: Date.now(),
    };
    setTasks(prev => [...prev, newTask]);
  };

  const editTask = (id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      // Recalculate XP if energy cost changes and XP wasn't manually set? 
      // For now, trust the updates passed.
      return { ...t, ...updates };
    }));
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  const completeTask = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (stats.energy < task.energyCost) {
      alert("طاقة غير كافية! خذ استراحة.");
      return;
    }

    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
      const today = new Date().toISOString().split('T')[0];

      // Streak Logic: Increase only if this is the first task completed today
      let newStreak = prev.streak;
      let lastTaskDate = prev.lastTaskCompletionDate;

      if (lastTaskDate !== today) {
        // Check if the last task was yesterday
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = yesterday.toISOString().split('T')[0];

        if (lastTaskDate === yesterdayStr) {
          newStreak += 1;
        } else {
          // Streak broken or started
          newStreak = 1; 
        }
        lastTaskDate = today;
      }

      let newXp = prev.currentXp + task.xpReward;
      let newLevel = prev.level;
      let newMaxXp = prev.maxXp;

      if (newXp >= newMaxXp) {
        newXp -= newMaxXp;
        newLevel += 1;
        newMaxXp = Math.floor(newMaxXp * LEVEL_SCALING_FACTOR);
      }

      return {
        ...prev,
        currentXp: newXp,
        level: newLevel,
        maxXp: newMaxXp,
        energy: prev.energy - task.energyCost,
        streak: newStreak,
        lastTaskCompletionDate: lastTaskDate
      };
    });
  };

  const resetProgress = () => {
    if (confirm("هل أنت متأكد من إعادة تعيين كل التقدم؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
    }
  };

  return (
    <GameContext.Provider value={{ stats, tasks, addTask, editTask, deleteTask, completeTask, resetProgress }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { X, Calendar } from 'lucide-react';
import { PillarType, Task } from '../types';
import { PILLARS } from '../constants';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [energyCost, setEnergyCost] = useState(10);
  const [dueDate, setDueDate] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setEnergyCost(initialData.energyCost);
        setDueDate(initialData.dueDate || '');
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        setEnergyCost(10);
        setDueDate('');
      }
    }
  }, [isOpen, initialData, defaultPillar]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    onSubmit({
      title,
      description,
      pillar,
      energyCost,
      dueDate,
      xpReward: Math.floor(energyCost * 1.5) // Auto-calc XP based on difficulty
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-800 w-full max-w-md rounded-2xl p-6 relative shadow-2xl">
        <button onClick={onClose} className="absolute top-4 left-4 text-neutral-500 hover:text-white transition-colors">
            <X size={24} />
        </button>

        <h3 className="text-xl font-bold text-white mb-6">
            {initialData ? 'تعديل المهمة' : 'مهمة جديدة'}
        </h3>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-xs text-neutral-400 mb-1">العنوان</label>
            <input 
                type="text" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none focus:ring-1 focus:ring-game-red"
                placeholder="ماذا تريد أن تنجز؟"
                autoFocus
            />
          </div>

          <div>
            <label className="block text-xs text-neutral-400 mb-1">الركن</label>
            <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                {PILLARS.map(p => (
                    <button
                        key={p.id}
                        type="button"
                        onClick={() => setPillar(p.id)}
                        className={`flex items-center gap-1 px-3 py-1.5 rounded-full text-xs font-bold border transition-all whitespace-nowrap
                            ${pillar === p.id 
                                ? `bg-neutral-100 text-black border-white` 
                                : 'bg-neutral-950 text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                        `}
                    >
                        <p.icon size={12} />
                        {p.label}
                    </button>
                ))}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
                 <label className="block text-xs text-neutral-400 mb-1">تاريخ الاستحقاق</label>
                 <div className="relative">
                    <input 
                        type="date" 
                        value={dueDate}
                        onChange={(e) => setDueDate(e.target.value)}
                        className="w-full bg-black border border-neutral-700 rounded-lg p-3 pl-3 text-white focus:border-game-red outline-none text-sm"
                    />
                    {/* Hack to force calendar icon color filter if needed, standard input works mostly */}
                 </div>
            </div>
            <div>
                 <label className="block text-xs text-neutral-400 mb-1">الطاقة المطلوبة: {energyCost}</label>
                 <input 
                    type="range" 
                    min="5" 
                    max="50" 
                    step="5"
                    value={energyCost}
                    onChange={(e) => setEnergyCost(Number(e.target.value))}
                    className="w-full accent-game-red h-10"
                />
            </div>
          </div>

          <div>
            <label className="block text-xs text-neutral-400 mb-1">الوصف (اختياري)</label>
            <textarea 
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none h-20 text-sm resize-none"
                placeholder="تفاصيل إضافية..."
            />
          </div>

          <button 
            type="submit" 
            className="w-full bg-white text-black font-bold py-3 rounded-xl hover:bg-neutral-200 transition-colors mt-2"
          >
            {initialData ? 'حفظ التغييرات' : 'إضافة المهمة'}
          </button>
        </form>
      </div>
    </div>
  );
};

import React from 'react';
import { Task } from '../types';
import { CheckCircle2, Trash2, Zap, Pencil, CalendarClock } from 'lucide-react';
import { PILLARS } from '../constants';

interface Props {
  task: Task;
  onComplete: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit?: (task: Task) => void;
  canAfford: boolean;
}

export const TaskItem: React.FC<Props> = ({ task, onComplete, onDelete, onEdit, canAfford }) => {
  const pillarInfo = PILLARS.find(p => p.id === task.pillar);

  // Format Date
  const isOverdue = task.dueDate && new Date(task.dueDate) < new Date(new Date().setHours(0,0,0,0));

  return (
    <div className={`
      relative p-4 rounded-xl border border-neutral-800 bg-neutral-900 mb-3 transition-all duration-300 group
      ${task.completed ? 'opacity-50 grayscale' : 'hover:border-neutral-600'}
    `}>
      <div className="flex justify-between items-start">
        <div className="flex-1 ml-2">

            {/* Meta Header */}
            <div className="flex items-center gap-2 mb-2 flex-wrap">
                {pillarInfo && (
                    <div className={`flex items-center gap-1 text-[10px] px-2 py-0.5 rounded bg-neutral-950 border border-neutral-800 ${pillarInfo.color}`}>
                         <pillarInfo.icon size={10} />
                        <span>{pillarInfo.label}</span>
                    </div>
                )}
                {task.dueDate && (
                     <div className={`flex items-center gap-1 text-[10px] px-2 py-0.5 rounded bg-neutral-950 border border-neutral-800 ${isOverdue && !task.completed ? 'text-red-500 border-red-900' : 'text-neutral-400'}`}>
                        <CalendarClock size={10} />
                        <span>{task.dueDate}</span>
                    </div>
                )}
            </div>

          <h4 className={`font-bold text-white text-lg leading-tight ${task.completed ? 'line-through decoration-game-red' : ''}`}>
            {task.title}
          </h4>
          {task.description && <p className="text-sm text-neutral-400 mt-1 leading-relaxed">{task.description}</p>}

          <div className="flex items-center mt-3 gap-3">
             <div className="flex items-center text-xs text-yellow-500 font-mono bg-neutral-950 px-2 py-1 rounded border border-neutral-800 shadow-sm">
                <Zap size={10} className="ml-1" /> 
                <span className="font-bold">-{task.energyCost}</span>
             </div>
             <div className="text-xs text-game-red font-mono font-bold">+{task.xpReward} XP</div>
          </div>
        </div>

        {/* Actions */}
        <div className="flex flex-col gap-2 pl-2">
            {!task.completed && (
                <button
                onClick={() => onComplete(task.id)}
                disabled={!canAfford}
                className={`
                    p-2.5 rounded-xl transition-all duration-200
                    ${canAfford 
                        ? 'bg-game-red text-white hover:bg-red-500 shadow-[0_0_15px_rgba(220,38,38,0.4)] hover:scale-105' 
                        : 'bg-neutral-800 text-neutral-600 cursor-not-allowed'}
                `}
                title={canAfford ? "إكمال المهمة" : "لا توجد طاقة كافية"}
                >
                <CheckCircle2 size={20} />
                </button>
            )}

            {!task.completed && onEdit && (
                <button
                    onClick={() => onEdit(task)}
                    className="p-2.5 text-neutral-500 hover:text-white hover:bg-neutral-800 rounded-xl transition-colors"
                >
                    <Pencil size={18} />
                </button>
            )}

            <button
                onClick={() => {
                    if(confirm('هل أنت متأكد من حذف هذه المهمة؟')) onDelete(task.id);
                }}
                className="p-2.5 text-neutral-600 hover:text-red-500 hover:bg-neutral-800 rounded-xl transition-colors"
            >
                <Trash2 size={18} />
            </button>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { PillarType, Task } from '../types';
import { useGame } from '../context/GameContext';
import { PillWidget } from './PillWidget';
import { TaskItem } from './TaskItem';
import { ArrowRight, Plus } from 'lucide-react';
import { PILLARS } from '../constants';

interface Props {
  pillarId: PillarType;
  onBack: () => void;
  onAddTask: () => void;
  onEditTask?: (task: Task) => void;
}

export const PillarDetailScreen: React.FC<Props> = ({ pillarId, onBack, onAddTask, onEditTask }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();

  const pillarTasks = tasks.filter(t => t.pillar === pillarId);
  const activeTasks = pillarTasks.filter(t => !t.completed);
  const completedTasks = pillarTasks.filter(t => t.completed);

  // Sorting: Newest first
  activeTasks.sort((a, b) => b.createdAt - a.createdAt);

  return (
    <div className="flex flex-col h-full bg-game-black animate-fade-in absolute inset-0 z-30">

      {/* Header Area */}
      <div className="relative">
        <button 
            onClick={onBack}
            className="absolute top-6 left-4 z-20 p-2 bg-black/50 backdrop-blur rounded-full text-white border border-neutral-700 hover:bg-neutral-800"
        >
            <ArrowRight size={20} />
        </button>
        <PillWidget pillarId={pillarId} taskCount={activeTasks.length} variant="header" />
      </div>

      {/* Task List */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 pb-24">

        {activeTasks.length === 0 && completedTasks.length === 0 && (
             <div className="flex flex-col items-center justify-center h-64 text-neutral-500 opacity-60">
                <p>لا توجد مهام نشطة</p>
                <p className="text-xs mt-2">اضغط على + لإضافة مهمة جديدة</p>
             </div>
        )}

        {/* Active Tasks */}
        {activeTasks.map(task => (
            <TaskItem 
                key={task.id}
                task={task}
                onComplete={completeTask}
                onDelete={deleteTask}
                onEdit={onEditTask}
                canAfford={stats.energy >= task.energyCost}
            />
        ))}

        {/* Completed Tasks Header */}
        {completedTasks.length > 0 && (
            <div className="pt-6 border-t border-neutral-900 mt-4">
                <h4 className="text-xs font-bold text-neutral-600 mb-4 uppercase tracking-widest flex items-center gap-2">
                    <span>المكتملة</span>
                    <span className="bg-neutral-800 text-neutral-500 px-1.5 rounded-md text-[10px]">{completedTasks.length}</span>
                </h4>
                {completedTasks.map(task => (
                    <TaskItem 
                        key={task.id}
                        task={task}
                        onComplete={completeTask}
                        onDelete={deleteTask}
                        // Completed tasks typically usually not editable or less important to edit
                        canAfford={true}
                    />
                ))}
            </div>
        )}
      </div>

      {/* FAB to Add Task */}
      <button 
        onClick={onAddTask}
        className="fixed bottom-8 left-6 bg-white text-black p-4 rounded-full shadow-[0_0_20px_rgba(255,255,255,0.3)] hover:scale-110 transition-transform z-40"
      >
        <Plus size={24} />
      </button>
    </div>
  );
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { PILLARS } from '../constants';
import { TaskItem } from './TaskItem';
import { PillarType, Task } from '../types';
import { Plus } from 'lucide-react';

