            </div>
        ) : (
            activePillarTasks.sort((a,b) => (a.completed === b.completed ? 0 : a.completed ? 1 : -1)).map(task => (
            <TaskItem 
                key={task.id} 
                task={task} 
                onComplete={completeTask} 
                onDelete={deleteTask}
                onEdit={onEditTask}
