import React, { useState } from 'react';
import { GameProvider } from './context/GameContext';
import { Dashboard } from './components/Dashboard';
import { PillarsView } from './components/PillarsView';
import { AICoach } from './components/AICoach';
import { AppTab, PillarType, StackScreen, Task } from './types';
import { LayoutDashboard, ListTodo, Bot, Settings } from 'lucide-react';
import { useGame } from './context/GameContext';
import { LearningScreen, StudyingScreen, ExerciseScreen, WorkScreen, EntertainmentScreen } from './components/PillarScreens';
import { TaskFormModal } from './components/TaskFormModal';

const AppContent: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [currentStackScreen, setCurrentStackScreen] = useState<StackScreen>('ROOT');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [modalDefaultPillar, setModalDefaultPillar] = useState<PillarType>('Learning');

  const { resetProgress, addTask, editTask } = useGame();

  const navigateToPillar = (pillar: PillarType) => {
    setActiveTab(AppTab.PILLARS); 
    setCurrentStackScreen(pillar);
  };

  const handleBack = () => {
    setCurrentStackScreen('ROOT');
    setActiveTab(AppTab.DASHBOARD);
  };

  // Handlers for Modal
  const openAddTask = (pillar?: PillarType) => {
    setEditingTask(null);
    setModalDefaultPillar(pillar || (currentStackScreen !== 'ROOT' ? (currentStackScreen as PillarType) : 'Learning'));
    setIsModalOpen(true);
  };

  const openEditTask = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const handleSaveTask = (taskData: Partial<Task>) => {
    if (editingTask) {
        editTask(editingTask.id, taskData);
    } else {
        addTask(taskData);
    }
    setIsModalOpen(false);
  };

  const renderContent = () => {
    // If we are in a specific pillar screen (Stack Navigation)
    if (currentStackScreen !== 'ROOT') {
        const props = { 
            onBack: handleBack, 
            onAddTask: () => openAddTask(currentStackScreen as PillarType),
            onEditTask: openEditTask
        };
        switch (currentStackScreen) {
            case 'Learning': return <LearningScreen {...props} />;
            case 'Studying': return <StudyingScreen {...props} />;
            case 'Exercise': return <ExerciseScreen {...props} />;
            case 'Work': return <WorkScreen {...props} />;
            case 'Entertainment': return <EntertainmentScreen {...props} />;
        }
    }

    // Default Tab Navigation
    switch (activeTab) {
      case AppTab.DASHBOARD: 
        return <Dashboard onNavigateToPillar={navigateToPillar} />;
      case AppTab.PILLARS: 
        return <PillarsView onAddTask={openAddTask} onEditTask={openEditTask} />;
      case AppTab.COACH: 
        return <AICoach />;
      default: 
        return <Dashboard onNavigateToPillar={navigateToPillar} />;
    }
  };

  return (
    <div className="min-h-screen bg-game-black text-white flex justify-center">
      <div className="w-full max-w-md h-screen flex flex-col relative bg-neutral-950 shadow-2xl overflow-hidden">

        {/* Header (Only show if not in stack screen) */}
        {currentStackScreen === 'ROOT' && (
            <header className="p-4 flex justify-between items-center border-b border-neutral-900 bg-game-black/50 backdrop-blur-md sticky top-0 z-20">
                <h1 className="text-xl font-black tracking-tighter text-white">
                    تطبيق <span className="text-game-red">التطوير</span>
                </h1>
                <button onClick={resetProgress} className="text-neutral-600 hover:text-red-500 transition-colors">
                    <Settings size={20} />
                </button>
            </header>
        )}

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto relative no-scrollbar">
            {renderContent()}
        </main>

        {/* Bottom Navigation (Hide in Detail Screen) */}
        {currentStackScreen === 'ROOT' && (
            <nav className="border-t border-neutral-800 bg-game-black pb-safe pt-2 px-4 absolute bottom-0 w-full z-20">
                <div className="flex justify-around items-center h-16">
                    <NavButton 
                        active={activeTab === AppTab.DASHBOARD} 
                        onClick={() => { setActiveTab(AppTab.DASHBOARD); setCurrentStackScreen('ROOT'); }} 
                        icon={LayoutDashboard} 
                        label="الرئيسية" 
                    />
                    <NavButton 
                        active={activeTab === AppTab.PILLARS} 
                        onClick={() => { setActiveTab(AppTab.PILLARS); setCurrentStackScreen('ROOT'); }} 
                        icon={ListTodo} 
                        label="المهام" 
                    />
                    <NavButton 
                        active={activeTab === AppTab.COACH} 
                        onClick={() => { setActiveTab(AppTab.COACH); setCurrentStackScreen('ROOT'); }} 
                        icon={Bot} 
                        label="المدرب" 
                    />
                </div>
            </nav>
        )}

        {/* Global Task Modal */}
        <TaskFormModal 
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            onSubmit={handleSaveTask}
            initialData={editingTask}
            defaultPillar={modalDefaultPillar}
        />

      </div>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ElementType; label: string }> = ({ active, onClick, icon: Icon, label }) => (
    <button 
        onClick={onClick}
        className={`flex flex-col items-center justify-center w-16 transition-all duration-300 ${active ? 'text-game-red -translate-y-2' : 'text-neutral-500'}`}
    >
        <div className={`p-2 rounded-xl ${active ? 'bg-game-red/10' : 'bg-transparent'}`}>
            <Icon size={24} className={active ? 'stroke-[2.5px]' : 'stroke-2'} />
        </div>
        <span className="text-[10px] font-bold mt-1">{label}</span>
    </button>
);

const App: React.FC = () => {
  return (
    <GameProvider>
      <AppContent />
    </GameProvider>
  );
};

export default App;

import React from 'react';

interface Props {
  size: number;
  strokeWidth: number;
  percentage: number;
  color: string;
  children?: React.ReactNode;
}

export const CircularProgress: React.FC<Props> = ({ size, strokeWidth, percentage, color, children }) => {
  const radius = (size - strokeWidth) / 2;
  const circumference = radius * 2 * Math.PI;
  const offset = circumference - (percentage / 100) * circumference;

  return (
    <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
      <svg width={size} height={size} className="transform -rotate-90">
        {/* Track Circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke="#262626"
          strokeWidth={strokeWidth}
          fill="transparent"
        />
        {/* Progress Circle */}
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke="currentColor"
          strokeWidth={strokeWidth}
          fill="transparent"
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          strokeLinecap="round"
          className={`circular-progress-circle ${color}`}
        />
      </svg>
      {/* Centered Content */}
      <div className="absolute inset-0 flex items-center justify-center">
        {children}
      </div>
    </div>
  );
};

import React from 'react';
import { LucideIcon } from 'lucide-react';
import { ProgressBar } from './ProgressBar';
import { CircularProgress } from './CircularProgress';

interface DashboardWidgetProps {
  label: string;
  value: string | number;
  subValue?: string;
  icon: LucideIcon;
  iconColor: string;
  progress?: {
    current: number;
    max: number;
    colorClass: string;
  };
  variant?: 'linear' | 'circular';
  borderColor?: string;
}

export const DashboardWidget: React.FC<DashboardWidgetProps> = ({
  label,
  value,
  subValue,
  icon: Icon,
  iconColor,
  progress,
  variant = 'linear',
  borderColor = 'border-neutral-800'
}) => {
  return (
    <div className={`bg-neutral-900 border ${borderColor} p-4 rounded-xl shadow-lg flex flex-col justify-between h-full relative overflow-hidden group transition-all duration-300 hover:scale-[1.02] hover:shadow-2xl`}>
      {/* Background Icon */}
      <div className="absolute -top-2 -right-2 p-2 opacity-5 group-hover:opacity-10 transition-opacity pointer-events-none">
        <Icon size={80} />
      </div>

      <div className="flex items-center justify-between mb-2 z-10">
        <span className="text-neutral-400 text-xs font-black uppercase tracking-widest">{label}</span>
        <Icon className={iconColor} size={18} />
      </div>

      <div className="z-10 flex-1 flex flex-col justify-end">
        {variant === 'circular' && progress ? (
            <div className="flex justify-center py-2">
                <CircularProgress 
                    size={100} 
                    strokeWidth={8} 
                    percentage={(progress.current / progress.max) * 100} 
                    color={progress.colorClass.replace('bg-', 'text-')}
                >
                    <div className="text-center">
                        <p className="text-3xl font-black text-white leading-none">{value}</p>
                        {subValue && <span className="text-[10px] text-neutral-500 font-bold uppercase">{subValue}</span>}
                    </div>
                </CircularProgress>
                <div className="absolute bottom-2 right-4 text-[10px] text-neutral-500 font-mono">
                    {progress.current} / {progress.max} XP
                </div>
            </div>
        ) : (
            <>
                <div className="flex items-baseline gap-2">
                    <p className="text-3xl font-black text-white">{value}</p>
                    {subValue && <span className="text-sm font-medium text-neutral-500">{subValue}</span>}
                </div>

                {progress && (
                    <div className="mt-3">
                        <ProgressBar 
                            current={progress.current} 
                            max={progress.max} 
                            colorClass={progress.colorClass} 
                            height="h-2" 
                            showText={false} 
                        />
                        <p className="text-[10px] text-right mt-1 text-neutral-500 font-mono">
                            {progress.current} / {progress.max}
                        </p>
                    </div>
                )}
            </>
        )}
      </div>
    </div>
  );
};

