import { UserStats, Task, BASE_XP_PER_LEVEL, PillarsData, PillarType, AppSettings } from '../types';
import { MAX_DAILY_ENERGY, PILLARS } from '../constants';

const STATS_KEY = 'game_stats';
const PILLARS_KEY = 'game_pillars';
const SETTINGS_KEY = 'game_settings';

export const defaultStats: UserStats = {
  level: 1,
  currentXp: 0,
  maxXp: BASE_XP_PER_LEVEL,
  energy: MAX_DAILY_ENERGY,
  maxEnergy: MAX_DAILY_ENERGY,
  streak: 0,
  lastLoginDate: new Date().toISOString().split('T')[0],
  lastTaskCompletionDate: '',
};

export const defaultSettings: AppSettings = {
  language: 'ar',
  themeColor: 'red-black',
  darkMode: true,
};

const emptyPillarsData: PillarsData = {
  Learning: [],
  Studying: [],
  Exercise: [],
  Work: [],
  Entertainment: []
};

export const StorageService = {
  saveStats: (stats: UserStats) => {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(stats));
    } catch (e) {
      console.error("Failed to save stats", e);
    }
  },

  loadStats: (): UserStats | null => {
    try {
      const data = localStorage.getItem(STATS_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error("Failed to load stats", e);
      return null;
    }
  },

  saveTasks: (tasks: Task[]) => {
    try {
      const pillarsData: PillarsData = { ...emptyPillarsData };
      tasks.forEach(task => {
        if (pillarsData[task.pillar]) {
          pillarsData[task.pillar].push(task);
        }
      });
      localStorage.setItem(PILLARS_KEY, JSON.stringify(pillarsData));
    } catch (e) {
      console.error("Failed to save pillars", e);
    }
  },

  loadTasks: (): Task[] => {
    try {
      const data = localStorage.getItem(PILLARS_KEY);
      if (!data) return [];

      const pillarsData: PillarsData = JSON.parse(data);
      let allTasks: Task[] = [];
      (Object.keys(pillarsData) as PillarType[]).forEach(key => {
        if (Array.isArray(pillarsData[key])) {
          allTasks = [...allTasks, ...pillarsData[key]];
        }
      });
      return allTasks;
    } catch (e) {
      console.error("Failed to load pillars", e);
      return [];
    }
  },

  saveSettings: (settings: AppSettings) => {
    try {
      localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
    } catch (e) {
      console.error("Failed to save settings", e);
    }
  },

  loadSettings: (): AppSettings => {
    try {
      const data = localStorage.getItem(SETTINGS_KEY);
      return data ? { ...defaultSettings, ...JSON.parse(data) } : defaultSettings;
    } catch (e) {
      return defaultSettings;
    }
  },

  clearAll: () => {
    localStorage.removeItem(STATS_KEY);
    localStorage.removeItem(PILLARS_KEY);
    localStorage.removeItem(SETTINGS_KEY);
  }
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppSettings, Language, ThemeColor } from '../types';
import { StorageService, defaultSettings } from '../services/storage';
import { translations, TranslationKey } from '../utils/translations';

interface SettingsContextType extends AppSettings {
  updateSettings: (updates: Partial<AppSettings>) => void;
  t: (key: TranslationKey) => string;
}

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export const SettingsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [settings, setSettings] = useState<AppSettings>(defaultSettings);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load settings on mount
  useEffect(() => {
    const loaded = StorageService.loadSettings();
    setSettings(loaded);
    setIsLoaded(true);
  }, []);

  // Apply Side Effects (CSS Variables & DOM attributes)
  useEffect(() => {
    if (!isLoaded) return;

    // 1. Language Direction
    document.documentElement.lang = settings.language;
    document.documentElement.dir = settings.language === 'ar' ? 'rtl' : 'ltr';

    // 2. Dark Mode (using CSS class mostly, but mostly handled by var overrides below)
    if (settings.darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }

    // 3. Theme Colors (Injecting into :root)
    const root = document.documentElement;
    let primary, primaryDim, bg, surface, accent;

    // Define Palettes
    if (settings.themeColor === 'blue-dark') {
      primary = '#3b82f6'; primaryDim = '#1e3a8a'; accent = '#60a5fa';
      bg = settings.darkMode ? '#0f172a' : '#f0f9ff';
      surface = settings.darkMode ? '#1e293b' : '#ffffff';
    } else if (settings.themeColor === 'green-matrix') {
      primary = '#22c55e'; primaryDim = '#14532d'; accent = '#4ade80';
      bg = settings.darkMode ? '#022c22' : '#f0fdf4';
      surface = settings.darkMode ? '#064e3b' : '#ffffff';
    } else if (settings.themeColor === 'purple-royal') {
      primary = '#a855f7'; primaryDim = '#581c87'; accent = '#c084fc';
      bg = settings.darkMode ? '#2e1065' : '#faf5ff';
      surface = settings.darkMode ? '#4c1d95' : '#ffffff';
    } else {
      // Red-Black (Default)
      primary = '#dc2626'; primaryDim = '#7f1d1d'; accent = '#ef4444';
      bg = settings.darkMode ? '#0a0a0a' : '#fef2f2';
      surface = settings.darkMode ? '#171717' : '#ffffff';
    }

    root.style.setProperty('--color-primary', primary);
    root.style.setProperty('--color-primary-dim', primaryDim);
    root.style.setProperty('--color-accent', accent);
    root.style.setProperty('--color-bg', bg);
    root.style.setProperty('--color-surface', surface);

    // Persist
    StorageService.saveSettings(settings);

  }, [settings, isLoaded]);

  const updateSettings = (updates: Partial<AppSettings>) => {
    setSettings(prev => ({ ...prev, ...updates }));
  };

  const t = (key: TranslationKey): string => {
    return translations[settings.language][key] || key;
  };

  return (
    <SettingsContext.Provider value={{ ...settings, updateSettings, t }}>
      {children}
    </SettingsContext.Provider>
  );
};

export const useSettings = () => {
  const context = useContext(SettingsContext);
  if (!context) throw new Error("useSettings must be used within a SettingsProvider");
  return context;
};

