import React from 'react';
import { useGame } from '../context/GameContext';
import { useSettings } from '../context/SettingsContext';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import { PILLARS } from '../constants';
import { Activity, Flame, Trophy, Zap, Settings } from 'lucide-react';
import { DashboardWidget } from './DashboardWidget';
import { PillWidget } from './PillWidget';
import { PillarType, AppTab } from '../types';

interface Props {
  onNavigateToPillar: (pillar: PillarType) => void;
  onOpenSettings: () => void;
}

export const Dashboard: React.FC<Props> = ({ onNavigateToPillar, onOpenSettings }) => {
  const { stats, tasks } = useGame();
  const { t } = useSettings();

  const completedTasksCount = tasks.filter(t => t.completed).length;

  // Calculate Tasks per Pillar
  const data = PILLARS.map(pillar => ({
    name: t(pillar.id.toLowerCase() as any) || pillar.label, // Fallback to translation based on ID
    value: tasks.filter(t => t.pillar === pillar.id && t.completed).length,
    color: pillar.color
  })).filter(d => d.value > 0);

  const chartData = data.length > 0 ? data : [{ name: t('noData'), value: 1, color: '#333' }];

  return (
    <div className="space-y-6 pb-24 animate-fade-in p-1">

      {/* Top Stats Grid */}
      <div className="grid grid-cols-2 gap-3">
        {/* Level & XP Widget - Circular */}
        <div className="col-span-1 row-span-2">
             <DashboardWidget 
                label={t('level')}
                value={stats.level}
                subValue="Level"
                icon={Trophy}
                iconColor="text-yellow-500"
                progress={{
                    current: stats.currentXp,
                    max: stats.maxXp,
                    colorClass: "bg-game-red"
                }}
                variant="circular"
                borderColor="border-game-red-dim"
            />
        </div>

        {/* Energy Widget */}
        <DashboardWidget 
            label={t('energy')}
            value={stats.energy}
            subValue={`/ ${stats.maxEnergy}`}
            icon={Zap}
            iconColor="text-yellow-400"
            progress={{
                current: stats.energy,
                max: stats.maxEnergy,
                colorClass: "bg-yellow-500"
            }}
        />

        {/* Streak Widget */}
        <div className="grid grid-cols-2 gap-3">
            <DashboardWidget 
                label={t('streak')}
                value={stats.streak}
                icon={Flame}
                iconColor="text-orange-500"
            />
             <DashboardWidget 
                label={t('completed')}
                value={completedTasksCount}
                icon={Activity}
                iconColor="text-blue-500"
            />
        </div>
      </div>

      {/* Life Pillars Grid */}
      <div className="animate-slide-up" style={{ animationDelay: '0.1s' }}>
         <div className="flex justify-between items-center mb-3 px-2 border-r-4 border-game-red">
            <h3 className="text-lg font-bold text-white">{t('lifePillars')}</h3>
            <button onClick={onOpenSettings} className="text-neutral-500 hover:text-white">
                <Settings size={20} />
            </button>
         </div>

        <div className="grid grid-cols-1 gap-3">
            {PILLARS.map((pillar, index) => {
                const count = tasks.filter(t => t.pillar === pillar.id && !t.completed).length;
                return (
                    <div key={pillar.id} className="animate-slide-up" style={{ animationDelay: `${0.1 + index * 0.05}s` }}>
                        <PillWidget 
                            pillarId={pillar.id} 
                            taskCount={count}
                            onClick={() => onNavigateToPillar(pillar.id)}
                        />
                    </div>
                );
            })}
        </div>
      </div>

      {/* Chart Section */}
      <div className="bg-game-dark border border-neutral-800 p-4 rounded-xl shadow-lg animate-slide-up" style={{ animationDelay: '0.4s' }}>
        <h3 className="text-sm font-bold mb-4 text-neutral-400 uppercase tracking-widest border-b border-neutral-800 pb-2">{t('distribution')}</h3>
        <div className="h-48 w-full flex items-center">
            <div className="flex-1 h-full">
                <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                        data={chartData}
                        cx="50%"
                        cy="50%"
                        innerRadius={40}
                        outerRadius={60}
                        paddingAngle={5}
                        dataKey="value"
                        stroke="none"
                    >
                    {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={data.length > 0 ? (entry as any).color.replace('text-', 'bg-').replace('-500', '-600') : '#333'} />
                    ))}
                    </Pie>
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#171717', border: '1px solid #333', borderRadius: '8px', fontSize: '12px' }}
                        itemStyle={{ color: '#fff' }}
                    />
                </PieChart>
                </ResponsiveContainer>
            </div>
            {/* Custom Legend */}
            <div className="flex-1 text-xs space-y-2">
                {data.slice(0, 5).map(d => (
                    <div key={d.name} className="flex items-center justify-end text-neutral-400">
                         <span className="font-bold text-white mr-2">{d.value}</span>
                         <span>{d.name}</span>
                        <div className={`w-2 h-2 rounded-full ml-2 ${d.color.replace('text-', 'bg-')}`}></div>
                    </div>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { PILLARS } from '../constants';
import { PillarType } from '../types';
import { ChevronLeft } from 'lucide-react';
import { useSettings } from '../context/SettingsContext';

interface Props {
  pillarId: PillarType;
  taskCount: number;
  onClick?: () => void;
  variant?: 'card' | 'header'; 
}

export const PillWidget: React.FC<Props> = ({ pillarId, taskCount, onClick, variant = 'card' }) => {
  const pillar = PILLARS.find(p => p.id === pillarId);
  const { t, language } = useSettings();

  if (!pillar) return null;

  const isCard = variant === 'card';
  const colorName = pillar.color.split('-')[1];
  const gradientClass = isCard ? `bg-gradient-to-l from-${colorName}-900/20 to-game-black` : 'bg-game-black';

  // Translation key based on ID
  const translatedLabel = t(pillar.id.toLowerCase() as any);

  return (
    <button 
      onClick={onClick}
      disabled={!onClick}
      className={`
        relative overflow-hidden w-full text-right transition-all duration-300 group
        ${isCard 
          ? `${gradientClass} border border-neutral-800 p-5 rounded-xl hover:border-${colorName}-500/50 hover:shadow-lg hover:shadow-${colorName}-900/20 active:scale-[0.98]` 
          : 'bg-game-black border-b border-neutral-800 p-8 pb-10'}
      `}
    >
      {/* Background Icon Effect */}
      <div className={`absolute ${isCard ? '-left-6 -bottom-6 opacity-10 rotate-12 group-hover:opacity-20 group-hover:rotate-0 transition-all duration-500' : 'right-4 top-1/2 -translate-y-1/2 opacity-5 scale-150'}`}>
        <pillar.icon size={isCard ? 100 : 120} />
      </div>

      <div className="relative z-10 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <div className={`
                flex items-center justify-center rounded-xl shadow-lg transition-transform duration-300 group-hover:scale-110
                ${isCard ? 'p-3 w-12 h-12' : 'p-2 w-10 h-10'}
                bg-neutral-900/80 backdrop-blur border border-neutral-700 ${pillar.color}
            `}>
                <pillar.icon size={isCard ? 24 : 20} />
            </div>
            <div>
                <h3 className={`font-black text-white leading-none mb-1 ${isCard ? 'text-xl' : 'text-3xl'}`}>
                    {translatedLabel}
                </h3>
                {isCard && (
                     <div className="flex items-center gap-2">
                        <span className={`text-xs font-bold ${taskCount > 0 ? 'text-white' : 'text-neutral-600'}`}>
                            {taskCount} {t('tasks')}
                        </span>
                        {taskCount > 0 && <span className="w-2 h-2 rounded-full bg-game-red animate-pulse"></span>}
                     </div>
                )}
            </div>
        </div>

        {/* Only show chevron if it's a clickable card */}
        {isCard && (
            <div className={`p-2 rounded-full bg-black/20 group-hover:bg-game-red group-hover:text-white transition-colors duration-300 text-neutral-600 ${language === 'en' ? 'rotate-180' : ''}`}>
