import { GoogleGenAI } from "@google/genai";
import { UserStats, Task, PlayerProfile } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) return null;
  return new GoogleGenAI({ apiKey });
};

export const getCoachAdvice = async (stats: UserStats, tasks: Task[], profile: PlayerProfile | null): Promise<string> => {
  const ai = getClient();
  if (!ai) return "الرجاء إعداد مفتاح API الخاص بـ Gemini للحصول على نصائح المدرب.";

  const pendingTasks = tasks.filter(t => !t.completed).length;
  const completedTasks = tasks.filter(t => t.completed).length;
  const playerName = profile?.name || "Player";

  const prompt = `
    You are a hardcore, motivating life-coach for a gamified productivity app called "Level Up Life".
    The user's name is "${playerName}".
    The user's current stats are:
    - Level: ${stats.level}
    - XP: ${stats.currentXp}/${stats.maxXp}
    - Energy: ${stats.energy}/${stats.maxEnergy}
    - Streak: ${stats.streak} days
    - Tasks Pending: ${pendingTasks}
    - Tasks Completed Today: ${completedTasks}

    The theme is Red and Black, aggressive but supportive.
    Give the user a short, punchy paragraph of advice (in Arabic) on what to focus on next.
    Refer to them by name occasionally.
    If energy is low, tell them to rest. If streak is high, congratulate them.
    Keep it under 50 words. Use emojis suitable for a game.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "استمر في التقدم يا بطل!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "المدرب في استراحة حالياً. حاول لاحقاً.";
  }
};

import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { getCoachAdvice } from '../services/geminiService';
import { Bot, RefreshCw } from 'lucide-react';

