      <h2 className="text-2xl font-bold text-white">مدربك الذكي</h2>
      <p className="text-neutral-400 text-sm">
        يستخدم الذكاء الاصطناعي لتحليل أدائك ومستوى طاقتك لتقديم النصيحة المثالية الآن.
      </p>

      {advice && (
        <div className="bg-neutral-900 border border-game-red p-6 rounded-xl shadow-lg w-full relative">
            <div className="absolute -top-3 right-4 bg-game-black px-2 text-game-red text-xs font-bold border border-game-red rounded">نصيحة</div>
            <p className="text-lg leading-relaxed text-white font-medium">"{advice}"</p>
        </div>
      )}

      <button
        onClick={askCoach}
        disabled={loading}
        className="flex items-center space-x-2 space-x-reverse bg-white text-black px-6 py-3 rounded-full font-bold active:scale-95 transition-transform disabled:opacity-50"
      >
        {loading ? (
            <RefreshCw className="animate-spin ml-2" size={20} />
