      </button>

        {!process.env.API_KEY && (
            <p className="text-xs text-red-500 mt-4">ملاحظة: لم يتم العثور على API_KEY. لن تعمل ميزة الذكاء الاصطناعي بشكل كامل.</p>
        )}
    </div>
  );
};

