import React, { useState, useEffect } from 'react';
import { X, Dumbbell, Zap, Trophy, Target } from 'lucide-react';
import { PillarType, Task } from '../types';
import { PILLARS, HOME_EXERCISES } from '../constants';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [energyCost, setEnergyCost] = useState(10);
  const [xpReward, setXpReward] = useState(15);
  const [dueDate, setDueDate] = useState('');

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setEnergyCost(initialData.energyCost);
        setXpReward(initialData.xpReward);
        setDueDate(initialData.dueDate || '');
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        setEnergyCost(10);
        setXpReward(15);
        setDueDate('');
      }
    }
  }, [isOpen, initialData, defaultPillar]);

  // Auto-update XP when energy changes (if not manually overridden in a complex way, keeping simple sync for custom tasks)
  const handleEnergyChange = (val: number) => {
    setEnergyCost(val);
    if (!initialData) {
        setXpReward(Math.floor(val * 1.5));
    }
  };

  const handleExerciseSelect = (ex: typeof HOME_EXERCISES[0]) => {
    setTitle(ex.name);
    setEnergyCost(ex.energyCost);
    setXpReward(ex.xpReward);
    setDescription(`الهدف: ${ex.reps || ex.duration}`);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    onSubmit({
      title,
      description,
      pillar,
      energyCost,
      xpReward,
      dueDate,
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-800 w-full max-w-md rounded-2xl p-6 relative shadow-2xl max-h-[90vh] overflow-y-auto no-scrollbar">
        <button onClick={onClose} className="absolute top-4 left-4 text-neutral-500 hover:text-white transition-colors z-10">
            <X size={24} />
        </button>

        <h3 className="text-xl font-bold text-white mb-6 sticky top-0 bg-neutral-900 z-0 pb-2 border-b border-neutral-800">
            {initialData ? 'تعديل المهمة' : 'مهمة جديدة'}
        </h3>

        <form onSubmit={handleSubmit} className="space-y-5">

          {/* Pillar Selector */}
          <div>
            <label className="block text-xs text-neutral-400 mb-2 font-bold uppercase">الركن</label>
            <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                {PILLARS.map(p => (
                    <button
                        key={p.id}
                        type="button"
                        onClick={() => setPillar(p.id)}
                        className={`flex items-center gap-1 px-3 py-2 rounded-xl text-xs font-bold border transition-all whitespace-nowrap
                            ${pillar === p.id 
                                ? `bg-neutral-100 text-black border-white shadow-lg scale-105` 
                                : 'bg-neutral-950 text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                        `}
                    >
                        <p.icon size={14} />
                        {p.label}
                    </button>
                ))}
            </div>
          </div>

          {/* Exercise Quick Select (Only visible if Exercise pillar is active) */}
          {pillar === 'Exercise' && (
            <div className="bg-neutral-950/50 p-3 rounded-xl border border-neutral-800">
                <div className="flex items-center gap-2 mb-3 text-green-500">
                    <Dumbbell size={16} />
                    <span className="text-xs font-bold uppercase tracking-widest">تمارين منزلية مقترحة</span>
                </div>
                <div className="grid grid-cols-2 gap-2 max-h-40 overflow-y-auto pr-1 custom-scrollbar">
                    {HOME_EXERCISES.map(ex => (
                        <button
                            key={ex.id}
                            type="button"
                            onClick={() => handleExerciseSelect(ex)}
                            className="bg-neutral-800 hover:bg-neutral-700 hover:border-green-500/50 border border-neutral-700 p-2 rounded-lg text-right transition-all group"
                        >
                            <div className="font-bold text-[11px] text-white group-hover:text-green-400 truncate">{ex.name}</div>
                            <div className="text-[9px] text-neutral-400 flex justify-between mt-1 items-center">
                                <span>{ex.reps || ex.duration}</span>
                                <div className="flex gap-1">
                                     <span className="text-yellow-500 font-mono">⚡{ex.energyCost}</span>
                                     <span className="text-game-red font-mono">XP{ex.xpReward}</span>
                                </div>
                            </div>
                        </button>
                    ))}
                </div>
            </div>
          )}

          {/* Title Input */}
          <div>
            <label className="block text-xs text-neutral-400 mb-1 font-bold">العنوان</label>
            <input 
                type="text" 
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none focus:ring-1 focus:ring-game-red transition-all"
                placeholder={pillar === 'Exercise' ? "مثال: تمرين ضغط مخصص" : "ماذا تريد أن تنجز؟"}
            />
          </div>

          {/* Stats Sliders */}
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-neutral-950 p-3 rounded-xl border border-neutral-800">
                 <label className="text-[10px] text-yellow-500 mb-2 font-bold flex items-center gap-1">
                    <Zap size={12} className="fill-yellow-500" />
                    تكلفة الطاقة: {energyCost}
                 </label>
                 <input 
                    type="range" 
                    min="5" 
                    max="50" 
                    step="5"
                    value={energyCost}
                    onChange={(e) => handleEnergyChange(Number(e.target.value))}
                    className="w-full accent-yellow-500 h-2 bg-neutral-800 rounded-lg appearance-none cursor-pointer"
                />
            </div>
            <div className="bg-neutral-950 p-3 rounded-xl border border-neutral-800">
                 <label className="text-[10px] text-game-red mb-2 font-bold flex items-center gap-1">
                    <Trophy size={12} className="fill-game-red" />
                    جائزة الخبرة: {xpReward}
                 </label>
                 <input 
                    type="range" 
                    min="10" 
                    max="100" 
                    step="5"
                    value={xpReward}
                    onChange={(e) => setXpReward(Number(e.target.value))}
                    className="w-full accent-game-red h-2 bg-neutral-800 rounded-lg appearance-none cursor-pointer"
                />
            </div>
          </div>

          {/* Details & Date */}
          <div className="grid grid-cols-2 gap-4">
             <div className="col-span-2">
                <label className="block text-xs text-neutral-400 mb-1 font-bold flex items-center gap-1">
                    <Target size={12} />
                    {pillar === 'Exercise' ? 'الهدف (تكرار / وقت)' : 'الوصف (اختياري)'}
                </label>
                <textarea 
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none h-20 text-sm resize-none"
                    placeholder={pillar === 'Exercise' ? "مثال: 3 جولات، راحة 30 ثانية" : "تفاصيل إضافية..."}
                />
             </div>
             <div className="col-span-2">
                 <label className="block text-xs text-neutral-400 mb-1 font-bold">تاريخ الاستحقاق</label>
                 <input 
                    type="date" 
                    value={dueDate}
                    onChange={(e) => setDueDate(e.target.value)}
                    className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none text-sm"
                 />
            </div>
          </div>

          <button 
            type="submit" 
            className="w-full bg-white text-black font-black py-4 rounded-xl hover:bg-neutral-200 hover:scale-[1.02] active:scale-[0.98] transition-all mt-2 shadow-lg"
          >
            {initialData ? 'حفظ التغييرات' : 'إضافة المهمة'}
          </button>
        </form>
      </div>
    </div>
  );
};

