                />
            </div>
            <div className="bg-neutral-950 p-3 rounded-xl border border-neutral-800">
                 <label className="text-[10px] text-game-red mb-2 font-bold flex items-center gap-1">
                    <Trophy size={12} className="fill-game-red" />
                    جائزة الخبرة: {xpReward}
                 </label>
                 <input 
                    type="range" 
                    min="10" 
                    max="100" 
                    step="5"
                    value={xpReward}
                    onChange={(e) => setXpReward(Number(e.target.value))}
                    className="w-full accent-game-red h-2 bg-neutral-800 rounded-lg appearance-none cursor-pointer"
                />
            </div>
          </div>

          {/* Details & Date */}
          <div className="grid grid-cols-2 gap-4">
             <div className="col-span-2">
