import React, { useState } from 'react';
import { useGame } from '../context/GameContext';
import { DAYS_OF_WEEK } from '../constants';
import { TaskItem } from './TaskItem';
import { DayOfWeek, Task } from '../types';
import { Calendar, CheckCircle2, Coffee, Plus } from 'lucide-react';
import { CircularProgress } from './CircularProgress';

interface Props {
  onAddTask: (day: DayOfWeek) => void;
  onEditTask: (task: Task) => void;
}

export const WeeklyPlanner: React.FC<Props> = ({ onAddTask, onEditTask }) => {
  const { tasks, completeTask, deleteTask, stats } = useGame();

  // State to track expanded days (default to today or Saturday)
  const [expandedDay, setExpandedDay] = useState<DayOfWeek | null>('Saturday');

  return (
    <div className="pb-24 animate-fade-in p-4 space-y-4">
        <div className="flex items-center gap-2 mb-2">
            <Calendar className="text-game-red" size={24} />
            <h2 className="text-2xl font-black text-white">المخطط الأسبوعي</h2>
        </div>

        {DAYS_OF_WEEK.map((day) => {
            const isRestDay = day.id === 'Friday';
            const dayTasks = tasks.filter(t => t.day === day.id);
            const completedCount = dayTasks.filter(t => t.completed).length;
            const totalCount = dayTasks.length;
            const progress = totalCount > 0 ? (completedCount / totalCount) * 100 : 0;
            const isExpanded = expandedDay === day.id;

            return (
                <div 
                    key={day.id} 
                    className={`
                        border rounded-2xl overflow-hidden transition-all duration-300
                        ${isRestDay 
                            ? 'bg-gradient-to-br from-emerald-900/20 to-neutral-900 border-emerald-900/50' 
                            : 'bg-neutral-900 border-neutral-800'}
                    `}
                >
                    {/* Header Card */}
                    <div 
                        onClick={() => setExpandedDay(isExpanded ? null : day.id)}
                        className="p-4 flex items-center justify-between cursor-pointer active:bg-white/5"
                    >
                        <div className="flex items-center gap-4">
                            {/* Day Icon / Progress */}
                            <div className="relative w-12 h-12 flex items-center justify-center">
                                {isRestDay ? (
                                    <Coffee className="text-emerald-500" size={24} />
                                ) : (
                                    <CircularProgress 
                                        size={48} 
                                        strokeWidth={4} 
                                        percentage={progress} 
                                        color={progress === 100 ? 'text-game-red' : 'text-neutral-600'}
                                    >
                                        <span className={`text-xs font-bold ${progress === 100 ? 'text-game-red' : 'text-neutral-500'}`}>
                                            {Math.round(progress)}%
                                        </span>
                                    </CircularProgress>
                                )}
                            </div>

                            <div>
                                <h3 className={`font-black text-lg ${isRestDay ? 'text-emerald-500' : 'text-white'}`}>
                                    {day.label}
                                </h3>
                                <p className="text-xs text-neutral-500">
                                    {isRestDay ? 'استشفاء وراحة' : `${completedCount} / ${totalCount} مكتملة`}
                                </p>
                            </div>
                        </div>

                        {/* Expand Icon */}
                        <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''} text-neutral-500`}>
                            ▼
                        </div>
                    </div>

                    {/* Expanded Content */}
                    <div className={`transition-all duration-300 overflow-hidden ${isExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
                        <div className="p-4 pt-0 border-t border-neutral-800/50">

                            {isRestDay ? (
                                <div className="py-6 text-center text-emerald-500/80">
                                    <p className="text-sm font-bold">😌 استمتع بيومك! لا مهام اليوم.</p>
                                </div>
                            ) : (
                                <>
                                    {dayTasks.length === 0 ? (
                                        <div className="py-8 text-center">
                                            <p className="text-neutral-600 text-sm mb-3">لا توجد مهام مجدولة</p>
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onAddTask(day.id); }}
                                                className="text-game-red text-xs font-bold border border-game-red/30 px-3 py-1.5 rounded-lg hover:bg-game-red/10"
                                            >
                                                + إضافة مهمة لـ {day.label}
                                            </button>
                                        </div>
                                    ) : (
                                        <div className="space-y-3 mt-4">
                                            {dayTasks.map(task => (
                                                <TaskItem 
                                                    key={task.id}
                                                    task={task}
                                                    onComplete={completeTask}
                                                    onDelete={deleteTask}
                                                    onEdit={onEditTask}
                                                    canAfford={stats.energy >= task.energyCost}
                                                />
                                            ))}
                                            <button 
                                                onClick={() => onAddTask(day.id)}
                                                className="w-full py-3 border border-dashed border-neutral-800 rounded-xl text-neutral-600 text-sm font-bold hover:text-white hover:border-neutral-600 transition-colors flex items-center justify-center gap-2"
                                            >
                                                <Plus size={16} /> إضافة المزيد
                                            </button>
                                        </div>
                                    )}
                                </>
                            )}
                        </div>
                    </div>
                </div>
            );
        })}
    </div>
  );
};

import React, { useState } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { SettingsProvider, useSettings } from './context/SettingsContext';
import { Dashboard } from './components/Dashboard';
import { PillarsView } from './components/PillarsView';
import { WeeklyPlanner } from './components/WeeklyPlanner';
import { AICoach } from './components/AICoach';
import { SettingsScreen } from './components/SettingsScreen';
import { SignUpScreen } from './components/SignUpScreen';
import { AppTab, PillarType, StackScreen, Task, DayOfWeek } from './types';
import { LayoutDashboard, ListTodo, Bot, Settings as SettingsIcon, CalendarDays } from 'lucide-react';
import { LearningScreen, StudyingScreen, ExerciseScreen, WorkScreen, EntertainmentScreen } from './components/PillarScreens';
import { TaskFormModal } from './components/TaskFormModal';

const AppContent: React.FC = () => {
  const { playerProfile, addTask, editTask } = useGame();
  const { t } = useSettings();

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [currentStackScreen, setCurrentStackScreen] = useState<StackScreen>('ROOT');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [modalDefaultPillar, setModalDefaultPillar] = useState<PillarType>('Learning');
  const [modalDefaultDay, setModalDefaultDay] = useState<DayOfWeek>('Saturday');

  // If no profile exists, show Sign Up
  if (!playerProfile) {
    return <SignUpScreen />;
  }

  const navigateToPillar = (pillar: PillarType) => {
    setActiveTab(AppTab.PILLARS); 
    setCurrentStackScreen(pillar);
  };

  const handleBack = () => {
    setCurrentStackScreen('ROOT');
    setActiveTab(AppTab.DASHBOARD);
  };

  // Handlers for Modal
  const openAddTask = (pillar?: PillarType, day?: DayOfWeek) => {
    setEditingTask(null);
    setModalDefaultPillar(pillar || (currentStackScreen !== 'ROOT' ? (currentStackScreen as PillarType) : 'Learning'));
    setModalDefaultDay(day || 'Saturday');
    setIsModalOpen(true);
  };

  const openEditTask = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const handleSaveTask = (taskData: Partial<Task>) => {
    if (editingTask) {
        editTask(editingTask.id, taskData);
    } else {
        addTask(taskData);
    }
    setIsModalOpen(false);
  };

  const renderContent = () => {
    // If we are in a specific pillar screen (Stack Navigation)
    if (currentStackScreen !== 'ROOT') {
        const props = { 
            onBack: handleBack, 
            onAddTask: () => openAddTask(currentStackScreen as PillarType),
            onEditTask: openEditTask
        };
        switch (currentStackScreen) {
            case 'Learning': return <LearningScreen {...props} />;
            case 'Studying': return <StudyingScreen {...props} />;
            case 'Exercise': return <ExerciseScreen {...props} />;
            case 'Work': return <WorkScreen {...props} />;
            case 'Entertainment': return <EntertainmentScreen {...props} />;
        }
    }

    // Default Tab Navigation
    switch (activeTab) {
      case AppTab.DASHBOARD: 
        return <Dashboard onNavigateToPillar={navigateToPillar} onOpenSettings={() => setActiveTab(AppTab.SETTINGS)} />;
      case AppTab.PLANNER:
        return <WeeklyPlanner onAddTask={(day) => openAddTask(undefined, day)} onEditTask={openEditTask} />;
      case AppTab.PILLARS: 
        return <PillarsView onAddTask={() => openAddTask()} onEditTask={openEditTask} />;
      case AppTab.COACH: 
        return <AICoach />;
      case AppTab.SETTINGS:
        return <SettingsScreen />;
      default: 
        return <Dashboard onNavigateToPillar={navigateToPillar} onOpenSettings={() => setActiveTab(AppTab.SETTINGS)} />;
    }
  };

  return (
    <div className="min-h-screen bg-game-black text-white flex justify-center font-sans">
      <div className="w-full max-w-md h-screen flex flex-col relative bg-game-black shadow-2xl overflow-hidden">

        {/* Header (Only show if not in stack screen) */}
        {currentStackScreen === 'ROOT' && (
            <header className="p-4 flex justify-between items-center border-b border-neutral-800 bg-game-black/80 backdrop-blur-md sticky top-0 z-20">
                <div className="flex flex-col">
                    <h1 className="text-xl font-black tracking-tighter text-white leading-none">
                        {t('appTitle')}
                    </h1>
                </div>
                <button 
                    onClick={() => setActiveTab(AppTab.SETTINGS)} 
                    className={`text-neutral-500 hover:text-game-red transition-colors ${activeTab === AppTab.SETTINGS ? 'text-game-red' : ''}`}
                >
                    <SettingsIcon size={20} />
                </button>
            </header>
        )}

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto relative no-scrollbar">
            {renderContent()}
        </main>

        {/* Bottom Navigation (Hide in Detail Screen) */}
        {currentStackScreen === 'ROOT' && (
            <nav className="border-t border-neutral-800 bg-game-black pb-safe pt-2 px-4 absolute bottom-0 w-full z-20">
                <div className="flex justify-between items-center h-16 px-2">
                    <NavButton 
                        active={activeTab === AppTab.DASHBOARD} 
                        onClick={() => { setActiveTab(AppTab.DASHBOARD); setCurrentStackScreen('ROOT'); }} 
                        icon={LayoutDashboard} 
                        label={t('dashboard')} 
                    />
                     <NavButton 
                        active={activeTab === AppTab.PLANNER} 
                        onClick={() => { setActiveTab(AppTab.PLANNER); setCurrentStackScreen('ROOT'); }} 
                        icon={CalendarDays} 
                        label="الأسبوع" 
                    />
                    <NavButton 
                        active={activeTab === AppTab.PILLARS} 
                        onClick={() => { setActiveTab(AppTab.PILLARS); setCurrentStackScreen('ROOT'); }} 
                        icon={ListTodo} 
                        label={t('pillars')} 
                    />
                    <NavButton 
                        active={activeTab === AppTab.COACH} 
                        onClick={() => { setActiveTab(AppTab.COACH); setCurrentStackScreen('ROOT'); }} 
                        icon={Bot} 
                        label={t('coach')} 
                    />
                </div>
            </nav>
        )}

        {/* Global Task Modal */}
        <TaskFormModal 
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            onSubmit={handleSaveTask}
            initialData={editingTask}
            defaultPillar={modalDefaultPillar}
            defaultDay={modalDefaultDay}
        />

      </div>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ElementType; label: string }> = ({ active, onClick, icon: Icon, label }) => (
    <button 
        onClick={onClick}
        className={`flex flex-col items-center justify-center w-14 transition-all duration-300 ${active ? 'text-game-red -translate-y-2' : 'text-neutral-500'}`}
    >
        <div className={`p-2 rounded-xl ${active ? 'bg-game-red/10' : 'bg-transparent'}`}>
            <Icon size={24} className={active ? 'stroke-[2.5px]' : 'stroke-2'} />
        </div>
        <span className="text-[10px] font-bold mt-1">{label}</span>
    </button>
);

const App: React.FC = () => {
  return (
    <SettingsProvider>
        <GameProvider>
            <AppContent />
        </GameProvider>
    </SettingsProvider>
  );
};

