import { UserStats, Task, BASE_XP_PER_LEVEL, PillarsData, PillarType, AppSettings, PlayerProfile } from '../types';
import { MAX_DAILY_ENERGY, PILLARS } from '../constants';

const STATS_KEY = 'game_stats';
const PILLARS_KEY = 'game_pillars';
const SETTINGS_KEY = 'game_settings';
const PLAYER_KEY = 'game_player';

export const defaultStats: UserStats = {
  level: 1,
  currentXp: 0,
  maxXp: BASE_XP_PER_LEVEL,
  energy: MAX_DAILY_ENERGY,
  maxEnergy: MAX_DAILY_ENERGY,
  streak: 0,
  lastLoginDate: new Date().toISOString().split('T')[0],
  lastTaskCompletionDate: '',
};

export const defaultSettings: AppSettings = {
  language: 'ar',
  themeColor: 'red-black',
  darkMode: true,
  notificationsEnabled: false,
};

const emptyPillarsData: PillarsData = {
  Learning: [],
  Studying: [],
  Exercise: [],
  Work: [],
  Entertainment: []
};

export const StorageService = {
  // --- Profile ---
  saveProfile: (profile: PlayerProfile) => {
    try {
        localStorage.setItem(PLAYER_KEY, JSON.stringify(profile));
    } catch (e) {
        console.error("Failed to save profile", e);
    }
  },

  loadProfile: (): PlayerProfile | null => {
    try {
        const data = localStorage.getItem(PLAYER_KEY);
        return data ? JSON.parse(data) : null;
    } catch (e) {
        return null;
    }
  },

  // --- Stats ---
  saveStats: (stats: UserStats) => {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(stats));
    } catch (e) {
      console.error("Failed to save stats", e);
    }
  },

  loadStats: (): UserStats | null => {
    try {
      const data = localStorage.getItem(STATS_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error("Failed to load stats", e);
      return null;
    }
  },

  // --- Tasks ---
  saveTasks: (tasks: Task[]) => {
    try {
      const pillarsData: PillarsData = { ...emptyPillarsData };
      tasks.forEach(task => {
        if (pillarsData[task.pillar]) {
          pillarsData[task.pillar].push(task);
        }
      });
      localStorage.setItem(PILLARS_KEY, JSON.stringify(pillarsData));
    } catch (e) {
      console.error("Failed to save pillars", e);
    }
  },

  loadTasks: (): Task[] => {
    try {
      const data = localStorage.getItem(PILLARS_KEY);
      if (!data) return [];

      const pillarsData: PillarsData = JSON.parse(data);
      let allTasks: Task[] = [];
      (Object.keys(pillarsData) as PillarType[]).forEach(key => {
        if (Array.isArray(pillarsData[key])) {
          allTasks = [...allTasks, ...pillarsData[key]];
        }
      });

      // Ensure tasks have order property if missing (migration)
      return allTasks.map((t, i) => ({
        ...t,
        order: t.order ?? i
      })).sort((a, b) => a.order - b.order);

    } catch (e) {
      console.error("Failed to load pillars", e);
      return [];
    }
  },

  // --- Settings ---
  saveSettings: (settings: AppSettings) => {
    try {
      localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
    } catch (e) {
      console.error("Failed to save settings", e);
    }
  },

  loadSettings: (): AppSettings => {
    try {
      const data = localStorage.getItem(SETTINGS_KEY);
      return data ? { ...defaultSettings, ...JSON.parse(data) } : defaultSettings;
    } catch (e) {
      return defaultSettings;
    }
  },

  // --- Utility ---
  clearAll: () => {
    localStorage.removeItem(STATS_KEY);
    localStorage.removeItem(PILLARS_KEY);
    localStorage.removeItem(SETTINGS_KEY);
    localStorage.removeItem(PLAYER_KEY);
  },

  initializeNewAccount: (profile: PlayerProfile) => {
    StorageService.saveProfile(profile);
    StorageService.saveStats(defaultStats);
    StorageService.saveTasks([]);
    StorageService.saveSettings(defaultSettings);
  }
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { GameState, Task, UserStats, PlayerProfile, LEVEL_SCALING_FACTOR } from '../types';
import { ENERGY_REGEN_PER_DAY } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { useToast } from './ToastContext';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const { addToast } = useToast();

  // Load from Storage
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedStats) setStats(loadedStats);
    if (loadedTasks) setTasks(loadedTasks);

    setIsLoaded(true);
  }, []);

  // Check Daily Reset
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    const today = new Date().toISOString().split('T')[0];

    setStats(prev => {
      if (prev.lastLoginDate === today) return prev;

      const updatedStats = {
        ...prev,
        energy: Math.min(prev.maxEnergy, prev.energy + ENERGY_REGEN_PER_DAY),
        lastLoginDate: today,
      };

      StorageService.saveStats(updatedStats);
      addToast('تم تجديد طاقتك اليومية! ⚡', 'info');
      return updatedStats;
    });
  }, [isLoaded, playerProfile, addToast]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = (data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats(defaultStats);
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  };

  const addTask = (taskData: Partial<Task>) => {
    const maxOrder = tasks.length > 0 ? Math.max(...tasks.map(t => t.order)) : 0;
    const newTask: Task = {
      id: crypto.randomUUID(),
      title: taskData.title || 'مهمة جديدة',
      description: taskData.description || '',
      pillar: taskData.pillar || 'Work',
      completed: false,
      energyCost: taskData.energyCost || 10,
      xpReward: taskData.xpReward || Math.floor((taskData.energyCost || 10) * 1.5),
      dueDate: taskData.dueDate,
      day: taskData.day,
      createdAt: Date.now(),
      order: maxOrder + 1,
    };
    setTasks(prev => [...prev, newTask]);
    addToast('تمت إضافة المهمة بنجاح', 'success');
  };

  const editTask = (id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;
      return { ...t, ...updates };
    }));
    addToast('تم حفظ التعديلات', 'success');
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  };

  const reorderTasks = (reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  };

  const moveTask = (taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        // Find the task index
        const index = prevTasks.findIndex(t => t.id === taskId);
        if (index === -1) return prevTasks;

        const task = prevTasks[index];
        // We need to find the adjacent task in the SAME view (Pillar or Day) logic is complex in global state.
        // Simplified approach: Re-sort by order, find global index, swap orders.
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);

        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }

        return [...sortedTasks];
      });
  };

  const completeTask = (id: string) => {
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    if (stats.energy < task.energyCost) {
      addToast("طاقة غير كافية! خذ استراحة.", 'error');
      return;
    }

    setTasks(prev => prev.map(t => t.id === id ? { ...t, completed: true } : t));

    setStats(prev => {
      const today = new Date().toISOString().split('T')[0];
      let newStreak = prev.streak;
      let lastTaskDate = prev.lastTaskCompletionDate;

      if (lastTaskDate !== today) {
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = yesterday.toISOString().split('T')[0];
        if (lastTaskDate === yesterdayStr) {
          newStreak += 1;
        } else {
          newStreak = 1; 
        }
        lastTaskDate = today;
      }

      let newXp = prev.currentXp + task.xpReward;
      let newLevel = prev.level;
      let newMaxXp = prev.maxXp;

      if (newXp >= newMaxXp) {
        newXp -= newMaxXp;
        newLevel += 1;
        newMaxXp = Math.floor(newMaxXp * LEVEL_SCALING_FACTOR);
        addToast(`🎉 مبروك! وصلت للمستوى ${newLevel}`, 'level-up');
      } else {
        addToast(`+${task.xpReward} XP | -${task.energyCost}⚡`, 'success');
      }

      return {
        ...prev,
        currentXp: newXp,
        level: newLevel,
        maxXp: newMaxXp,
        energy: prev.energy - task.energyCost,
        streak: newStreak,
        lastTaskCompletionDate: lastTaskDate
      };
    });
  };

  const resetProgress = () => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  };

  return (
    <GameContext.Provider value={{ stats, tasks, playerProfile, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress }}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { Task } from '../types';
import { CheckCircle2, Trash2, Zap, Pencil, CalendarClock, Circle, ChevronUp, ChevronDown } from 'lucide-react';
import { PILLARS } from '../constants';
import { useGame } from '../context/GameContext';

interface Props {
  task: Task;
  onComplete: (id: string) => void;
  onDelete: (id: string) => void;
  onEdit?: (task: Task) => void;
  canAfford: boolean;
}

export const TaskItem: React.FC<Props> = ({ task, onComplete, onDelete, onEdit, canAfford }) => {
  const { moveTask } = useGame();
  const pillarInfo = PILLARS.find(p => p.id === task.pillar);
  const [isVisible, setIsVisible] = useState(false);
  const [isCompleting, setIsCompleting] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setIsVisible(true), 50);
    return () => clearTimeout(timer);
  }, []);

  const handleComplete = () => {
    setIsCompleting(true);
    setTimeout(() => {
        onComplete(task.id);
        setIsCompleting(false);
    }, 300);
  };

  const isOverdue = task.dueDate && new Date(task.dueDate) < new Date(new Date().setHours(0,0,0,0));

  return (
    <div 
        className={`
            relative p-4 rounded-2xl border mb-3 transition-all duration-500 group overflow-hidden
            ${isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}
            ${task.completed 
                ? 'bg-neutral-950/50 border-neutral-900 opacity-60 grayscale' 
                : 'bg-neutral-900 border-neutral-800 hover:border-neutral-700 shadow-md hover:shadow-xl hover:translate-x-1'}
            ${isCompleting ? 'scale-95 opacity-0' : 'scale-100'}
        `}
    >
      {/* Selection Line */}
      {!task.completed && (
        <div className={`absolute right-0 top-0 bottom-0 w-1 ${pillarInfo?.color.replace('text-', 'bg-')} opacity-0 group-hover:opacity-100 transition-opacity`} />
      )}

      <div className="flex justify-between items-start">
        <div className="flex-1 ml-2">

            {/* Meta Header */}
            <div className="flex items-center gap-2 mb-2 flex-wrap">
                {pillarInfo && (
                    <div className={`flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md bg-black/40 border border-neutral-800 ${pillarInfo.color}`}>
                         <pillarInfo.icon size={10} />
                        <span>{pillarInfo.label}</span>
                    </div>
                )}
                {task.dueDate && (
                     <div className={`flex items-center gap-1 text-[10px] font-bold px-2 py-1 rounded-md bg-black/40 border border-neutral-800 ${isOverdue && !task.completed ? 'text-red-500 border-red-900/50' : 'text-neutral-500'}`}>
                        <CalendarClock size={10} />
                        <span>{task.dueDate}</span>
                    </div>
                )}
            </div>

          <h4 className={`font-bold text-white text-lg leading-snug transition-all ${task.completed ? 'line-through text-neutral-500' : 'group-hover:text-gray-100'}`}>
            {task.title}
          </h4>
          {task.description && <p className="text-sm text-neutral-400 mt-2 leading-relaxed font-light">{task.description}</p>}

          {/* Rewards */}
          {!task.completed && (
            <div className="flex items-center mt-4 gap-3">
                <div className="flex items-center text-[10px] text-yellow-500 font-mono bg-yellow-500/10 px-2 py-1 rounded border border-yellow-500/20">
                    <Zap size={10} className="ml-1 fill-yellow-500" /> 
                    <span className="font-bold">-{task.energyCost} طاقة</span>
                </div>
                <div className="text-[10px] text-game-red font-mono font-bold bg-game-red/10 px-2 py-1 rounded border border-game-red/20">
                    +{task.xpReward} XP
                </div>
            </div>
          )}
        </div>

        {/* Actions & Reordering */}
        <div className="flex flex-col gap-1 pl-2 items-center">
            {/* Reorder Buttons (Only visible if not completed) */}
            {!task.completed && (
                <div className="flex flex-col gap-1 mb-2 opacity-50 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => moveTask(task.id, 'up')} className="p-1 hover:bg-neutral-800 rounded text-neutral-500 hover:text-white">
                        <ChevronUp size={16} />
                    </button>
                    <button onClick={() => moveTask(task.id, 'down')} className="p-1 hover:bg-neutral-800 rounded text-neutral-500 hover:text-white">
                        <ChevronDown size={16} />
                    </button>
                </div>
            )}

            {!task.completed && (
                <button
                onClick={handleComplete}
                disabled={!canAfford || isCompleting}
                className={`
                    p-3 rounded-xl transition-all duration-300
                    ${canAfford 
                        ? 'bg-neutral-800 text-neutral-400 hover:bg-game-red hover:text-white hover:scale-110 shadow-lg' 
                        : 'bg-neutral-900 text-neutral-700 cursor-not-allowed'}
                `}
                title={canAfford ? "إكمال المهمة" : "لا توجد طاقة كافية"}
                >
                {canAfford ? <CheckCircle2 size={22} /> : <Circle size={22} className="stroke-neutral-700" />}
                </button>
            )}

            {!task.completed && onEdit && (
                <button
                    onClick={() => onEdit(task)}
                    className="p-3 text-neutral-600 hover:text-white hover:bg-neutral-800 rounded-xl transition-colors scale-90 hover:scale-100"
                >
                    <Pencil size={18} />
                </button>
            )}

            <button
                onClick={() => {
                    if(confirm('هل أنت متأكد من حذف هذه المهمة؟')) onDelete(task.id);
                }}
                className="p-3 text-neutral-600 hover:text-red-500 hover:bg-neutral-800/50 rounded-xl transition-colors scale-90 hover:scale-100"
            >
                <Trash2 size={18} />
            </button>
        </div>
      </div>
    </div>
  );
};

