}

// Toast Types
export type ToastType = 'success' | 'error' | 'info' | 'level-up';
export interface ToastMessage {
  id: string;
  message: string;
  type: ToastType;
}

import { UserStats, Task, BASE_XP_PER_LEVEL, PillarsData, PillarType, AppSettings, PlayerProfile } from '../types';
import { MAX_DAILY_ENERGY, PILLARS } from '../constants';

const STATS_KEY = 'game_stats';
const PILLARS_KEY = 'game_pillars';
const SETTINGS_KEY = 'game_settings';
const PLAYER_KEY = 'game_player';

export const defaultStats: UserStats = {
  level: 1,
  currentXp: 0,
  maxXp: BASE_XP_PER_LEVEL,
  energy: MAX_DAILY_ENERGY,
  maxEnergy: MAX_DAILY_ENERGY,
  streak: 0,
  lastLoginDate: new Date().toISOString().split('T')[0],
  lastTaskCompletionDate: '',
  lastEnergyUpdate: Date.now(),
};

export const defaultSettings: AppSettings = {
  language: 'ar',
  themeColor: 'red-black',
  darkMode: true,
  notificationsEnabled: false,
};

const emptyPillarsData: PillarsData = {
  Learning: [],
  Studying: [],
  Exercise: [],
  Work: [],
  Entertainment: []
};

export const StorageService = {
  // --- Profile ---
  saveProfile: (profile: PlayerProfile) => {
    try {
        localStorage.setItem(PLAYER_KEY, JSON.stringify(profile));
    } catch (e) {
        console.error("Failed to save profile", e);
    }
  },

  loadProfile: (): PlayerProfile | null => {
    try {
        const data = localStorage.getItem(PLAYER_KEY);
        return data ? JSON.parse(data) : null;
    } catch (e) {
        return null;
    }
  },

  // --- Stats ---
  saveStats: (stats: UserStats) => {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(stats));
    } catch (e) {
      console.error("Failed to save stats", e);
    }
  },

  loadStats: (): UserStats | null => {
    try {
      const data = localStorage.getItem(STATS_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error("Failed to load stats", e);
      return null;
    }
  },

  // --- Tasks ---
  saveTasks: (tasks: Task[]) => {
    try {
      const pillarsData: PillarsData = { ...emptyPillarsData };
      tasks.forEach(task => {
        if (pillarsData[task.pillar]) {
          pillarsData[task.pillar].push(task);
        }
      });
      localStorage.setItem(PILLARS_KEY, JSON.stringify(pillarsData));
    } catch (e) {
      console.error("Failed to save pillars", e);
    }
  },

  loadTasks: (): Task[] => {
    try {
      const data = localStorage.getItem(PILLARS_KEY);
      if (!data) return [];

      const pillarsData: PillarsData = JSON.parse(data);
      let allTasks: Task[] = [];
      (Object.keys(pillarsData) as PillarType[]).forEach(key => {
        if (Array.isArray(pillarsData[key])) {
          allTasks = [...allTasks, ...pillarsData[key]];
        }
      });

      // Ensure tasks have order property if missing (migration)
      return allTasks.map((t, i) => ({
        ...t,
        order: t.order ?? i
      })).sort((a, b) => a.order - b.order);

    } catch (e) {
      console.error("Failed to load pillars", e);
      return [];
    }
  },

  // --- Settings ---
  saveSettings: (settings: AppSettings) => {
    try {
      localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
    } catch (e) {
      console.error("Failed to save settings", e);
    }
  },

  loadSettings: (): AppSettings => {
    try {
      const data = localStorage.getItem(SETTINGS_KEY);
      return data ? { ...defaultSettings, ...JSON.parse(data) } : defaultSettings;
    } catch (e) {
      return defaultSettings;
    }
  },

  // --- Utility ---
  clearAll: () => {
    localStorage.removeItem(STATS_KEY);
    localStorage.removeItem(PILLARS_KEY);
    localStorage.removeItem(SETTINGS_KEY);
    localStorage.removeItem(PLAYER_KEY);
  },

  initializeNewAccount: (profile: PlayerProfile) => {
    StorageService.saveProfile(profile);
    StorageService.saveStats(defaultStats);
    StorageService.saveTasks([]);
    StorageService.saveSettings(defaultSettings);
  }
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { GameState, Task, UserStats, PlayerProfile } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_RATES } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { useToast } from './ToastContext';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const { addToast } = useToast();

  // Load from Storage
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedStats) setStats(loadedStats);
    if (loadedTasks) setTasks(loadedTasks);

    setIsLoaded(true);
  }, []);

  // --- Energy Regeneration System ---
  const regenerateEnergy = useCallback(() => {
    setStats(prev => {
        const now = Date.now();
        const lastUpdate = prev.lastEnergyUpdate || now;
        const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);

        // Update if enough time has passed (e.g. at least 1 minute of recovery value)
        if (diffInHours <= 0) return prev;

        const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);

        if (energyRecovered > 0 && prev.energy < prev.maxEnergy) {
            const newEnergy = Math.min(prev.maxEnergy, prev.energy + energyRecovered);
            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: now
            };
        }

        // Even if no energy recovered, update timestamp to prevent huge jumps later if maxed
        if (prev.energy >= prev.maxEnergy) {
            return { ...prev, lastEnergyUpdate: now };
        }

        return prev;
    });
  }, []);

  // Run regeneration on load and interval
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    // Initial catch-up calculation
    regenerateEnergy();

    // Periodic update every minute
    const interval = setInterval(regenerateEnergy, 60000);
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, regenerateEnergy]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats(defaultStats);
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;

        // Enforce automatic rates based on pillar
        const pillar = taskData.pillar || 'Work';
        const rates = PILLAR_RATES[pillar];

        const newTask: Task = {
          id: crypto.randomUUID(),
          title: taskData.title || 'مهمة جديدة',
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          energyCost: rates.energy, // Automatic
          xpReward: rates.xp,       // Automatic
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
        };
        return [...prev, newTask];
    });
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;

      // Recalculate rates if pillar changed
      let newRates = { energy: t.energyCost, xp: t.xpReward };
      if (updates.pillar && updates.pillar !== t.pillar) {
         newRates = PILLAR_RATES[updates.pillar];
      }

      return { 
          ...t, 
          ...updates,
          energyCost: newRates.energy,
          xpReward: newRates.xp
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);

        if (sortedIndex === -1) return prevTasks;

        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }

        return [...sortedTasks];
      });
  }, []);

  // --- Core Gameplay Loop: Task Completion ---
  const completeTask = useCallback((id: string) => {
    // 1. Check Task Existence and Energy
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    // Use strictly defined rates to prevent tampering
    const rates = PILLAR_RATES[task.pillar];

    if (stats.energy < rates.energy) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        return;
    }

    // 2. Mark as Completed
    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    // 3. Update Stats (Energy, XP, Level, Streak)
    setStats(prev => {
        // --- Streak Calculation ---
        const today = new Date().toISOString().split('T')[0];
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayStr = yesterday.toISOString().split('T')[0];

            if (lastTaskDate === yesterdayStr) {
                newStreak += 1;
            } else {
                newStreak = 1; // Reset streak if missed a day
            }
            lastTaskDate = today;
        }

        // --- XP & Level Calculation ---
        let currentXp = prev.currentXp + rates.xp;
        let level = prev.level;
        let maxXp = prev.maxXp;
        let didLevelUp = false;

        // While loop for multi-leveling
        // Formula: xpToNextLevel = Math.floor(100 * Math.pow(1.1, level - 1))
        while (currentXp >= maxXp) {
            currentXp -= maxXp;
            level += 1;
            maxXp = Math.floor(100 * Math.pow(1.1, level - 1));
            didLevelUp = true;
        }

        if (didLevelUp) {
            addToast(`🎉 مبروك! وصلت للمستوى ${level}`, 'level-up');
        } else {
            addToast(`+${rates.xp} XP | -${rates.energy}⚡`, 'success');
        }

        return {
            ...prev,
            energy: prev.energy - rates.energy,
            currentXp,
            level,
            maxXp,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            // Ensure timestamp is updated so regeneration doesn't apply immediately to consumed energy
            lastEnergyUpdate: Date.now() 
        };
    });
  }, [tasks, stats.energy, addToast]);


  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  }, [addToast]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    createProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress
  }), [stats, tasks, playerProfile, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { X, Dumbbell, Zap, Trophy, Target, Calendar } from 'lucide-react';
import { PillarType, Task, DayOfWeek } from '../types';
import { PILLARS, HOME_EXERCISES, DAYS_OF_WEEK, PILLAR_RATES } from '../constants';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
  defaultDay?: DayOfWeek;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar, defaultDay }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [day, setDay] = useState<DayOfWeek>('Saturday');
  const [dueDate, setDueDate] = useState('');

  // Auto-calculated rates based on current pillar
  const currentRates = PILLAR_RATES[pillar];

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setDay(initialData.day || 'Saturday');
        setDueDate(initialData.dueDate || '');
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        setDay(defaultDay || 'Saturday');
        setDueDate('');
      }
    }
  }, [isOpen, initialData, defaultPillar, defaultDay]);

  const handleExerciseSelect = (ex: typeof HOME_EXERCISES[0]) => {
    setTitle(ex.name);
    // Note: We ignore the custom energyCost in the predefined list now to enforce the "Pillar" rule strictness,
    // Or we could strictly set the pillar to Exercise. 
    // For consistency with the "Auto" prompt, we rely on the Pillar's base rate, 
    // OR we could technically pass these overrides if we wanted, but the prompt said "Calculated Automatically".
    // We will set the title and desc, but the cost/reward comes from the logic.
    setPillar('Exercise');
    setDescription(`الهدف: ${ex.reps || ex.duration}`);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;

    if (day === 'Friday') {
        alert("الجمعة يوم راحة! لا يمكنك إضافة مهام.");
        return;
    }

    onSubmit({
      title,
      description,
      pillar,
      day,
      dueDate,
      // Energy and XP are handled automatically by the context based on Pillar
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-800 w-full max-w-md rounded-2xl p-6 relative shadow-2xl max-h-[90vh] overflow-y-auto no-scrollbar">
        <button onClick={onClose} className="absolute top-4 left-4 text-neutral-500 hover:text-white transition-colors z-10">
            <X size={24} />
