import { UserStats, Task, BASE_XP_PER_LEVEL, PillarsData, PillarType, AppSettings, PlayerProfile } from '../types';
import { MAX_DAILY_ENERGY, PILLARS } from '../constants';

const STATS_KEY = 'game_stats';
const PILLARS_KEY = 'game_pillars';
const SETTINGS_KEY = 'game_settings';
const PLAYER_KEY = 'game_player';

export const defaultStats: UserStats = {
  level: 1,
  currentXp: 0,
  maxXp: BASE_XP_PER_LEVEL,
  energy: MAX_DAILY_ENERGY,
  maxEnergy: MAX_DAILY_ENERGY,
  streak: 0,
  lastLoginDate: new Date().toISOString().split('T')[0],
  lastTaskCompletionDate: '',
  lastEnergyUpdate: Date.now(),
  quranPagesRead: 0,
  quranBadges: 0,
};

export const defaultSettings: AppSettings = {
  language: 'ar',
  themeColor: 'red-black',
  darkMode: true,
  notificationsEnabled: false,
};

const emptyPillarsData: PillarsData = {
  Learning: [],
  Studying: [],
  Exercise: [],
  Work: [],
  Entertainment: [],
  Quran: []
};

export const StorageService = {
  // --- Profile ---
  saveProfile: (profile: PlayerProfile) => {
    try {
        localStorage.setItem(PLAYER_KEY, JSON.stringify(profile));
    } catch (e) {
        console.error("Failed to save profile", e);
    }
  },

  loadProfile: (): PlayerProfile | null => {
    try {
        const data = localStorage.getItem(PLAYER_KEY);
        return data ? JSON.parse(data) : null;
    } catch (e) {
        return null;
    }
  },

  // --- Stats ---
  saveStats: (stats: UserStats) => {
    try {
      localStorage.setItem(STATS_KEY, JSON.stringify(stats));
    } catch (e) {
      console.error("Failed to save stats", e);
    }
  },

  loadStats: (): UserStats | null => {
    try {
      const data = localStorage.getItem(STATS_KEY);
      return data ? JSON.parse(data) : null;
    } catch (e) {
      console.error("Failed to load stats", e);
      return null;
    }
  },

  // --- Tasks ---
  saveTasks: (tasks: Task[]) => {
    try {
      const pillarsData: PillarsData = { ...emptyPillarsData };
      tasks.forEach(task => {
        if (pillarsData[task.pillar]) {
          pillarsData[task.pillar].push(task);
        }
      });
      localStorage.setItem(PILLARS_KEY, JSON.stringify(pillarsData));
    } catch (e) {
      console.error("Failed to save pillars", e);
    }
  },

  loadTasks: (): Task[] => {
    try {
      const data = localStorage.getItem(PILLARS_KEY);
      if (!data) return [];

      const pillarsData: PillarsData = JSON.parse(data);
      let allTasks: Task[] = [];
      (Object.keys(pillarsData) as PillarType[]).forEach(key => {
        if (Array.isArray(pillarsData[key])) {
          allTasks = [...allTasks, ...pillarsData[key]];
        }
      });

      // Ensure tasks have order property if missing (migration)
      return allTasks.map((t, i) => ({
        ...t,
        order: t.order ?? i
      })).sort((a, b) => a.order - b.order);

    } catch (e) {
      console.error("Failed to load pillars", e);
      return [];
    }
  },

  // --- Settings ---
  saveSettings: (settings: AppSettings) => {
    try {
      localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
    } catch (e) {
      console.error("Failed to save settings", e);
    }
  },

  loadSettings: (): AppSettings => {
    try {
      const data = localStorage.getItem(SETTINGS_KEY);
      return data ? { ...defaultSettings, ...JSON.parse(data) } : defaultSettings;
    } catch (e) {
      return defaultSettings;
    }
  },

  // --- Utility ---
  clearAll: () => {
    localStorage.removeItem(STATS_KEY);
    localStorage.removeItem(PILLARS_KEY);
    localStorage.removeItem(SETTINGS_KEY);
    localStorage.removeItem(PLAYER_KEY);
  },

  initializeNewAccount: (profile: PlayerProfile) => {
    StorageService.saveProfile(profile);
    StorageService.saveStats(defaultStats);
    StorageService.saveTasks([]);
    StorageService.saveSettings(defaultSettings);
  }
};

import React, { createContext, useContext, useEffect, useState, useCallback, useMemo } from 'react';
import { GameState, Task, UserStats, PlayerProfile } from '../types';
import { ENERGY_RECOVERY_RATE, PILLAR_RATES, PAGES_PER_JUZ } from '../constants';
import { StorageService, defaultStats } from '../services/storage';
import { useToast } from './ToastContext';

interface GameContextType extends GameState {
  createProfile: (profileData: Omit<PlayerProfile, 'createdAt'>) => void;
  addTask: (task: Partial<Task>) => void;
  editTask: (id: string, updates: Partial<Task>) => void;
  deleteTask: (id: string) => void;
  completeTask: (id: string) => void;
  reorderTasks: (reorderedTasks: Task[]) => void;
  moveTask: (taskId: string, direction: 'up' | 'down') => void;
  resetProgress: () => void;
}

const GameContext = createContext<GameContextType | undefined>(undefined);

export const GameProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [stats, setStats] = useState<UserStats>(defaultStats);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [playerProfile, setPlayerProfile] = useState<PlayerProfile | null>(null);
  const [isLoaded, setIsLoaded] = useState(false);
  const { addToast } = useToast();

  // Load from Storage
  useEffect(() => {
    const loadedProfile = StorageService.loadProfile();
    const loadedStats = StorageService.loadStats();
    const loadedTasks = StorageService.loadTasks();

    if (loadedProfile) setPlayerProfile(loadedProfile);
    if (loadedStats) setStats(loadedStats);
    if (loadedTasks) setTasks(loadedTasks);

    setIsLoaded(true);
  }, []);

  // --- Energy Regeneration System ---
  const regenerateEnergy = useCallback(() => {
    setStats(prev => {
        const now = Date.now();
        const lastUpdate = prev.lastEnergyUpdate || now;
        const diffInHours = (now - lastUpdate) / (1000 * 60 * 60);

        // Update if enough time has passed (e.g. at least 1 minute of recovery value)
        if (diffInHours <= 0) return prev;

        const energyRecovered = Math.floor(diffInHours * ENERGY_RECOVERY_RATE);

        if (energyRecovered > 0 && prev.energy < prev.maxEnergy) {
            const newEnergy = Math.min(prev.maxEnergy, prev.energy + energyRecovered);
            return {
                ...prev,
                energy: newEnergy,
                lastEnergyUpdate: now
            };
        }

        // Even if no energy recovered, update timestamp to prevent huge jumps later if maxed
        if (prev.energy >= prev.maxEnergy) {
            return { ...prev, lastEnergyUpdate: now };
        }

        return prev;
    });
  }, []);

  // Run regeneration on load and interval
  useEffect(() => {
    if (!isLoaded || !playerProfile) return;

    // Initial catch-up calculation
    regenerateEnergy();

    // Periodic update every minute
    const interval = setInterval(regenerateEnergy, 60000);
    return () => clearInterval(interval);
  }, [isLoaded, playerProfile, regenerateEnergy]);

  // Save to Storage on change
  useEffect(() => {
    if (isLoaded && playerProfile) {
      StorageService.saveStats(stats);
      StorageService.saveTasks(tasks);
    }
  }, [stats, tasks, isLoaded, playerProfile]);

  const createProfile = useCallback((data: Omit<PlayerProfile, 'createdAt'>) => {
    const newProfile: PlayerProfile = {
        ...data,
        createdAt: new Date().toISOString()
    };
    StorageService.initializeNewAccount(newProfile);
    setPlayerProfile(newProfile);
    setStats(defaultStats);
    setTasks([]);
    addToast('أهلاً بك في رحلة التطوير! 🚀', 'success');
  }, [addToast]);

  const addTask = useCallback((taskData: Partial<Task>) => {
    setTasks(prev => {
        const maxOrder = prev.length > 0 ? Math.max(...prev.map(t => t.order)) : 0;

        // Enforce automatic rates based on pillar
        const pillar = taskData.pillar || 'Work';
        const rates = PILLAR_RATES[pillar];

        const newTask: Task = {
          id: crypto.randomUUID(),
          title: taskData.title || (pillar === 'Quran' ? 'ورد القرآن' : 'مهمة جديدة'),
          description: taskData.description || '',
          pillar: pillar,
          completed: false,
          energyCost: rates.energy, // Automatic
          xpReward: rates.xp,       // Automatic
          dueDate: taskData.dueDate,
          day: taskData.day,
          createdAt: Date.now(),
          order: maxOrder + 1,
          pages: taskData.pages // Specific for Quran
        };
        return [...prev, newTask];
    });
    addToast('تمت إضافة المهمة بنجاح', 'success');
  }, [addToast]);

  const editTask = useCallback((id: string, updates: Partial<Task>) => {
    setTasks(prev => prev.map(t => {
      if (t.id !== id) return t;

      // Recalculate rates if pillar changed
      let newRates = { energy: t.energyCost, xp: t.xpReward };
      if (updates.pillar && updates.pillar !== t.pillar) {
         newRates = PILLAR_RATES[updates.pillar];
      }

      return { 
          ...t, 
          ...updates,
          energyCost: newRates.energy,
          xpReward: newRates.xp
      };
    }));
    addToast('تم حفظ التعديلات', 'success');
  }, [addToast]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
    addToast('تم حذف المهمة', 'info');
  }, [addToast]);

  const reorderTasks = useCallback((reorderedTasks: Task[]) => {
      setTasks(reorderedTasks);
  }, []);

  const moveTask = useCallback((taskId: string, direction: 'up' | 'down') => {
      setTasks(prevTasks => {
        const sortedTasks = [...prevTasks].sort((a, b) => a.order - b.order);
        const sortedIndex = sortedTasks.findIndex(t => t.id === taskId);

        if (sortedIndex === -1) return prevTasks;

        if (direction === 'up' && sortedIndex > 0) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex - 1].order;
            sortedTasks[sortedIndex - 1].order = tempOrder;
        } else if (direction === 'down' && sortedIndex < sortedTasks.length - 1) {
            const tempOrder = sortedTasks[sortedIndex].order;
            sortedTasks[sortedIndex].order = sortedTasks[sortedIndex + 1].order;
            sortedTasks[sortedIndex + 1].order = tempOrder;
        }

        return [...sortedTasks];
      });
  }, []);

  // --- Core Gameplay Loop: Task Completion ---
  const completeTask = useCallback((id: string) => {
    // 1. Check Task Existence and Energy
    const task = tasks.find(t => t.id === id);
    if (!task || task.completed) return;

    // Use strictly defined rates to prevent tampering
    const rates = PILLAR_RATES[task.pillar];

    // Only check energy if not Quran (Quran has 0 cost)
    if (task.pillar !== 'Quran' && stats.energy < rates.energy) {
        addToast("طاقة غير كافية! خذ استراحة.", 'error');
        return;
    }

    // 2. Mark as Completed
    setTasks(currentTasks => currentTasks.map(t => t.id === id ? { ...t, completed: true } : t));

    // 3. Update Stats (Energy, XP, Level, Streak, Quran)
    setStats(prev => {
        // --- Streak Calculation ---
        const today = new Date().toISOString().split('T')[0];
        let newStreak = prev.streak;
        let lastTaskDate = prev.lastTaskCompletionDate;

        if (lastTaskDate !== today) {
            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayStr = yesterday.toISOString().split('T')[0];

            if (lastTaskDate === yesterdayStr) {
                newStreak += 1;
            } else {
                newStreak = 1; // Reset streak if missed a day
            }
            lastTaskDate = today;
        }

        let newStats = { 
            ...prev,
            streak: newStreak,
            lastTaskCompletionDate: lastTaskDate,
            lastEnergyUpdate: Date.now()
        };

        // --- Special Logic: Quran ---
        if (task.pillar === 'Quran') {
            const pagesToAdd = task.pages || 1;
            const oldTotalPages = prev.quranPagesRead || 0;
            const newTotalPages = oldTotalPages + pagesToAdd;

            // Calculate Badges (Juz completion)
            const oldJuzCount = Math.floor(oldTotalPages / PAGES_PER_JUZ);
            const newJuzCount = Math.floor(newTotalPages / PAGES_PER_JUZ);

            let badges = prev.quranBadges || 0;
            if (newJuzCount > oldJuzCount) {
                badges += (newJuzCount - oldJuzCount);
                addToast(`🎉 تبارك الله! أكملت جزءاً جديداً من القرآن`, 'badge');
            } else {
                addToast(`✅ تمت القراءة: ${pagesToAdd} صفحة`, 'success');
            }

            newStats.quranPagesRead = newTotalPages;
            newStats.quranBadges = badges;
        } 
        else {
            // --- Standard Logic: Energy & XP ---
            newStats.energy = prev.energy - rates.energy;

            let currentXp = prev.currentXp + rates.xp;
            let level = prev.level;
            let maxXp = prev.maxXp;
            let didLevelUp = false;

            // While loop for multi-leveling
            // Formula: xpToNextLevel = Math.floor(100 * Math.pow(1.1, level - 1))
            while (currentXp >= maxXp) {
                currentXp -= maxXp;
                level += 1;
                maxXp = Math.floor(100 * Math.pow(1.1, level - 1));
                didLevelUp = true;
            }

            if (didLevelUp) {
                addToast(`🎉 مبروك! وصلت للمستوى ${level}`, 'level-up');
            } else {
                addToast(`+${rates.xp} XP | -${rates.energy}⚡`, 'success');
            }

            newStats.currentXp = currentXp;
            newStats.level = level;
            newStats.maxXp = maxXp;
        }

        return newStats;
    });
  }, [tasks, stats.energy, addToast]);


  const resetProgress = useCallback(() => {
    if (confirm("هل أنت متأكد من حذف الحساب وإعادة البدء؟")) {
      StorageService.clearAll();
      setStats(defaultStats);
      setTasks([]);
      setPlayerProfile(null);
      addToast('تم إعادة تعيين الحساب', 'info');
    }
  }, [addToast]);

  const value = useMemo(() => ({
    stats,
    tasks,
    playerProfile,
    createProfile,
    addTask,
    editTask,
    deleteTask,
    completeTask, 
    reorderTasks,
    moveTask,
    resetProgress
  }), [stats, tasks, playerProfile, createProfile, addTask, editTask, deleteTask, completeTask, reorderTasks, moveTask, resetProgress]);

  return (
    <GameContext.Provider value={value}>
      {children}
    </GameContext.Provider>
  );
};

export const useGame = () => {
  const context = useContext(GameContext);
  if (!context) throw new Error("useGame must be used within a GameProvider");
  return context;
};

import React, { useState, useEffect } from 'react';
import { X, Dumbbell, Zap, Trophy, Target, Calendar, Scroll } from 'lucide-react';
import { PillarType, Task, DayOfWeek } from '../types';
import { PILLARS, HOME_EXERCISES, DAYS_OF_WEEK, PILLAR_RATES } from '../constants';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (taskData: Partial<Task>) => void;
  initialData?: Task | null;
  defaultPillar?: PillarType;
  defaultDay?: DayOfWeek;
}

export const TaskFormModal: React.FC<Props> = ({ isOpen, onClose, onSubmit, initialData, defaultPillar, defaultDay }) => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [pillar, setPillar] = useState<PillarType>('Learning');
  const [day, setDay] = useState<DayOfWeek>('Saturday');
  const [dueDate, setDueDate] = useState('');
  const [pages, setPages] = useState<number>(1); // For Quran

  // Auto-calculated rates based on current pillar
  const currentRates = PILLAR_RATES[pillar];

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setTitle(initialData.title);
        setDescription(initialData.description);
        setPillar(initialData.pillar);
        setDay(initialData.day || 'Saturday');
        setDueDate(initialData.dueDate || '');
        setPages(initialData.pages || 1);
      } else {
        setTitle('');
        setDescription('');
        setPillar(defaultPillar || 'Learning');
        setDay(defaultDay || 'Saturday');
        setDueDate('');
        setPages(1);
      }
    }
  }, [isOpen, initialData, defaultPillar, defaultDay]);

  const handleExerciseSelect = (ex: typeof HOME_EXERCISES[0]) => {
    setTitle(ex.name);
    setPillar('Exercise');
    setDescription(`الهدف: ${ex.reps || ex.duration}`);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // For Quran, title can be auto-generated if empty
    let finalTitle = title;
    if (pillar === 'Quran' && !finalTitle.trim()) {
        finalTitle = `قراءة ${pages} صفحة`;
    }

    if (!finalTitle.trim()) return;

    if (day === 'Friday' && pillar !== 'Quran') {
        alert("الجمعة يوم راحة! يمكنك قراءة القرآن فقط.");
        return;
    }

    onSubmit({
      title: finalTitle,
      description,
      pillar,
      day,
      dueDate,
      pages: pillar === 'Quran' ? Number(pages) : undefined
    });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-neutral-900 border border-neutral-800 w-full max-w-md rounded-2xl p-6 relative shadow-2xl max-h-[90vh] overflow-y-auto no-scrollbar">
        <button onClick={onClose} className="absolute top-4 left-4 text-neutral-500 hover:text-white transition-colors z-10">
            <X size={24} />
        </button>

        <h3 className="text-xl font-bold text-white mb-6 sticky top-0 bg-neutral-900 z-0 pb-2 border-b border-neutral-800">
            {initialData ? 'تعديل المهمة' : 'مهمة جديدة'}
        </h3>

        <form onSubmit={handleSubmit} className="space-y-5">

          {/* Day Selector */}
          <div>
            <label className="block text-xs text-neutral-400 mb-2 font-bold uppercase flex items-center gap-1">
                <Calendar size={12} /> اليوم
            </label>
            <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                {DAYS_OF_WEEK.map(d => (
                    <button
                        key={d.id}
                        type="button"
                        onClick={() => setDay(d.id)}
                        className={`
                            flex items-center justify-center px-4 py-2 rounded-xl text-xs font-bold border transition-all whitespace-nowrap
                            ${d.id === 'Friday' && pillar !== 'Quran' ? 'opacity-50 border-dashed border-neutral-700' : ''}
                            ${day === d.id 
                                ? 'bg-game-red text-white border-game-red shadow-lg' 
                                : 'bg-neutral-950 text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                        `}
                    >
                        {d.label}
                    </button>
                ))}
            </div>
            {day === 'Friday' && pillar !== 'Quran' && (
                <p className="text-[10px] text-yellow-500 mt-1 font-bold">⚠️ الجمعة يوم راحة (متاح للقرآن فقط).</p>
            )}
          </div>

          {/* Pillar Selector */}
          <div>
            <label className="block text-xs text-neutral-400 mb-2 font-bold uppercase">الركن</label>
            <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                {PILLARS.map(p => (
                    <button
                        key={p.id}
                        type="button"
                        onClick={() => setPillar(p.id)}
                        className={`flex items-center gap-1 px-3 py-2 rounded-xl text-xs font-bold border transition-all whitespace-nowrap
                            ${pillar === p.id 
                                ? `bg-neutral-100 text-black border-white shadow-lg scale-105` 
                                : 'bg-neutral-950 text-neutral-500 border-neutral-800 hover:border-neutral-600'}
                        `}
                    >
                        <p.icon size={14} />
                        {p.label}
                    </button>
                ))}
            </div>
          </div>

          {/* Special Input for Quran Pages */}
          {pillar === 'Quran' ? (
              <div className="bg-emerald-900/20 border border-emerald-900 p-4 rounded-xl">
                 <label className="block text-xs text-emerald-500 mb-2 font-bold flex items-center gap-1">
                    <Scroll size={14} /> عدد الصفحات
                </label>
                <div className="flex items-center gap-4">
                    <button type="button" onClick={() => setPages(p => Math.max(1, p - 1))} className="bg-neutral-800 w-10 h-10 rounded-lg text-white font-bold">-</button>
                    <input 
                        type="number"
                        value={pages}
                        onChange={(e) => setPages(Math.max(1, parseInt(e.target.value) || 0))}
                        className="flex-1 bg-black border border-neutral-700 rounded-lg p-3 text-center text-white text-xl font-black outline-none focus:border-emerald-500"
                    />
                    <button type="button" onClick={() => setPages(p => p + 1)} className="bg-neutral-800 w-10 h-10 rounded-lg text-white font-bold">+</button>
                </div>
                <p className="text-[10px] text-neutral-500 mt-2 text-center">كل 20 صفحة (جزء) تمنحك وساماً خاصاً.</p>
              </div>
          ) : (
            <>
                {/* Regular Title Input */}
                <div>
                    <label className="block text-xs text-neutral-400 mb-1 font-bold">العنوان</label>
                    <input 
                        type="text" 
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none focus:ring-1 focus:ring-game-red transition-all"
                        placeholder={pillar === 'Exercise' ? "مثال: تمرين ضغط مخصص" : "ماذا تريد أن تنجز؟"}
                    />
                </div>

                 {/* Exercise Quick Select */}
                 {pillar === 'Exercise' && (
                    <div className="bg-neutral-950/50 p-3 rounded-xl border border-neutral-800">
                        <div className="flex items-center gap-2 mb-3 text-green-500">
                            <Dumbbell size={16} />
                            <span className="text-xs font-bold uppercase tracking-widest">تمارين منزلية مقترحة</span>
                        </div>
                        <div className="grid grid-cols-2 gap-2 max-h-40 overflow-y-auto pr-1 custom-scrollbar">
                            {HOME_EXERCISES.map(ex => (
                                <button
                                    key={ex.id}
                                    type="button"
                                    onClick={() => handleExerciseSelect(ex)}
                                    className="bg-neutral-800 hover:bg-neutral-700 hover:border-green-500/50 border border-neutral-700 p-2 rounded-lg text-right transition-all group"
                                >
                                    <div className="font-bold text-[11px] text-white group-hover:text-green-400 truncate">{ex.name}</div>
                                    <div className="text-[9px] text-neutral-400 flex justify-between mt-1 items-center">
                                        <span>{ex.reps || ex.duration}</span>
                                    </div>
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </>
          )}


          {/* Stats Display (Automatic) */}
          {pillar !== 'Quran' && (
            <div className="grid grid-cols-2 gap-4">
                <div className="bg-neutral-950 p-3 rounded-xl border border-neutral-800 flex items-center justify-between">
                    <label className="text-[10px] text-yellow-500 font-bold flex items-center gap-1">
                        <Zap size={12} className="fill-yellow-500" />
                        التكلفة
                    </label>
                    <span className="text-xl font-black text-white">{currentRates.energy}</span>
                </div>
                <div className="bg-neutral-950 p-3 rounded-xl border border-neutral-800 flex items-center justify-between">
                    <label className="text-[10px] text-game-red font-bold flex items-center gap-1">
                        <Trophy size={12} className="fill-game-red" />
                        المكافأة
                    </label>
                    <span className="text-xl font-black text-white">{currentRates.xp}</span>
                </div>
            </div>
          )}

          {/* Details & Date (Hidden for Quran to keep it simple) */}
          {pillar !== 'Quran' && (
            <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                    <label className="block text-xs text-neutral-400 mb-1 font-bold flex items-center gap-1">
                        <Target size={12} />
                        {pillar === 'Exercise' ? 'الهدف (تكرار / وقت)' : 'الوصف (اختياري)'}
                    </label>
                    <textarea 
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        className="w-full bg-black border border-neutral-700 rounded-lg p-3 text-white focus:border-game-red outline-none h-20 text-sm resize-none"
                        placeholder={pillar === 'Exercise' ? "مثال: 3 جولات، راحة 30 ثانية" : "تفاصيل إضافية..."}
                    />
                </div>
            </div>
          )}

          <button 
            type="submit" 
            disabled={day === 'Friday' && pillar !== 'Quran'}
            className={`
                w-full text-black font-black py-4 rounded-xl transition-all mt-2 shadow-lg
                ${day === 'Friday' && pillar !== 'Quran' ? 'bg-neutral-700 cursor-not-allowed text-neutral-500' : 'bg-white hover:bg-neutral-200 hover:scale-[1.02] active:scale-[0.98]'}
            `}
          >
            {day === 'Friday' && pillar !== 'Quran' ? 'يوم راحة' : (initialData ? 'حفظ التغييرات' : 'جدولة المهمة')}
          </button>
        </form>
      </div>
    </div>
  );
};

import React from 'react';
import { PillarDetailScreen } from './PillarDetailScreen';

interface ScreenProps {
    onBack: () => void;
    onAddTask: () => void;
}

export const LearningScreen: React.FC<ScreenProps> = (props) => <PillarDetailScreen pillarId="Learning" {...props} />;
export const StudyingScreen: React.FC<ScreenProps> = (props) => <PillarDetailScreen pillarId="Studying" {...props} />;
export const ExerciseScreen: React.FC<ScreenProps> = (props) => <PillarDetailScreen pillarId="Exercise" {...props} />;
export const WorkScreen: React.FC<ScreenProps> = (props) => <PillarDetailScreen pillarId="Work" {...props} />;
export const EntertainmentScreen: React.FC<ScreenProps> = (props) => <PillarDetailScreen pillarId="Entertainment" {...props} />;
export const QuranScreen: React.FC<ScreenProps> = (props) => <PillarDetailScreen pillarId="Quran" {...props} />;

import React, { useState } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { SettingsProvider, useSettings } from './context/SettingsContext';
import { ToastProvider } from './context/ToastContext';
import { Dashboard } from './components/Dashboard';
import { PillarsView } from './components/PillarsView';
import { WeeklyPlanner } from './components/WeeklyPlanner';
import { AICoach } from './components/AICoach';
import { SettingsScreen } from './components/SettingsScreen';
import { SignUpScreen } from './components/SignUpScreen';
import { ToastSystem } from './components/ToastSystem';
import { AppTab, PillarType, StackScreen, Task, DayOfWeek } from './types';
import { Settings as SettingsIcon, ArrowRight } from 'lucide-react';
import { LearningScreen, StudyingScreen, ExerciseScreen, WorkScreen, EntertainmentScreen, QuranScreen } from './components/PillarScreens';
import { TaskFormModal } from './components/TaskFormModal';

const AppContent: React.FC = () => {
  const { playerProfile, addTask, editTask } = useGame();
  const { t } = useSettings();

  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [currentStackScreen, setCurrentStackScreen] = useState<StackScreen>('ROOT');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<Task | null>(null);
  const [modalDefaultPillar, setModalDefaultPillar] = useState<PillarType>('Learning');
  const [modalDefaultDay, setModalDefaultDay] = useState<DayOfWeek>('Saturday');

  // If no profile exists, show Sign Up
  if (!playerProfile) {
    return (
        <>
            <SignUpScreen />
            <ToastSystem />
        </>
    );
  }

  const navigateToPillar = (pillar: PillarType) => {
    setActiveTab(AppTab.PILLARS); 
    setCurrentStackScreen(pillar);
  };

  const handleBack = () => {
    setCurrentStackScreen('ROOT');
    setActiveTab(AppTab.DASHBOARD);
  };

  const goHome = () => {
    setActiveTab(AppTab.DASHBOARD);
    setCurrentStackScreen('ROOT');
  };

  // Handlers for Modal
  const openAddTask = (pillar?: PillarType, day?: DayOfWeek) => {
    setEditingTask(null);
    setModalDefaultPillar(pillar || (currentStackScreen !== 'ROOT' ? (currentStackScreen as PillarType) : 'Learning'));
    setModalDefaultDay(day || 'Saturday');
    setIsModalOpen(true);
  };

  const openEditTask = (task: Task) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  const handleSaveTask = (taskData: Partial<Task>) => {
    if (editingTask) {
        editTask(editingTask.id, taskData);
    } else {
        addTask(taskData);
    }
    setIsModalOpen(false);
  };

  const renderContent = () => {
    // If we are in a specific pillar screen (Stack Navigation)
    if (currentStackScreen !== 'ROOT') {
        const props = { 
            onBack: handleBack, 
            onAddTask: () => openAddTask(currentStackScreen as PillarType),
            onEditTask: openEditTask
        };
        switch (currentStackScreen) {
            case 'Learning': return <LearningScreen {...props} />;
            case 'Studying': return <StudyingScreen {...props} />;
            case 'Exercise': return <ExerciseScreen {...props} />;
            case 'Work': return <WorkScreen {...props} />;
            case 'Entertainment': return <EntertainmentScreen {...props} />;
            case 'Quran': return <QuranScreen {...props} />;
        }
    }

    // Default Tab Navigation
    switch (activeTab) {
      case AppTab.DASHBOARD: 
        return <Dashboard 
                  onNavigateToPillar={navigateToPillar} 
                  onOpenSettings={() => setActiveTab(AppTab.SETTINGS)} 
                  onNavigateToTab={setActiveTab}
               />;
      case AppTab.PLANNER:
        return <WeeklyPlanner onAddTask={(day) => openAddTask(undefined, day)} onEditTask={openEditTask} />;
      case AppTab.PILLARS: 
        return <PillarsView onAddTask={() => openAddTask()} onEditTask={openEditTask} />;
      case AppTab.COACH: 
        return <AICoach />;
      case AppTab.SETTINGS:
        return <SettingsScreen />;
      default: 
        return <Dashboard 
                  onNavigateToPillar={navigateToPillar} 
                  onOpenSettings={() => setActiveTab(AppTab.SETTINGS)} 
                  onNavigateToTab={setActiveTab}
               />;
    }
  };

  return (
    <div className="min-h-screen bg-game-black text-white flex justify-center font-sans">
      <div className="w-full max-w-md h-screen flex flex-col relative bg-game-black shadow-2xl overflow-hidden">

        {/* Header (Only show if not in stack screen) */}
        {currentStackScreen === 'ROOT' && (
            <header className="p-4 flex justify-between items-center border-b border-neutral-800 bg-game-black/80 backdrop-blur-md sticky top-0 z-20">
                <div className="flex items-center gap-3">
                    {activeTab !== AppTab.DASHBOARD && (
                        <button onClick={goHome} className="text-neutral-400 hover:text-white">
                            <ArrowRight size={24} />
                        </button>
                    )}
                    <h1 className="text-xl font-black tracking-tighter text-white leading-none">
                        {t('appTitle')}
                    </h1>
                </div>
                <button 
                    onClick={() => setActiveTab(AppTab.SETTINGS)} 
                    className={`text-neutral-500 hover:text-game-red transition-colors ${activeTab === AppTab.SETTINGS ? 'text-game-red' : ''}`}
                >
                    <SettingsIcon size={20} />
                </button>
            </header>
        )}

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto relative no-scrollbar">
            {renderContent()}
        </main>

        {/* Global Task Modal */}
        <TaskFormModal 
            isOpen={isModalOpen}
            onClose={() => setIsModalOpen(false)}
            onSubmit={handleSaveTask}
            initialData={editingTask}
            defaultPillar={modalDefaultPillar}
            defaultDay={modalDefaultDay}
        />

        {/* Toasts Overlay */}
        <ToastSystem />

      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <SettingsProvider>
        <ToastProvider>
            <GameProvider>
                <AppContent />
            </GameProvider>
        </ToastProvider>
    </SettingsProvider>
  );
};

export default App;

import React from 'react';
import { useToast } from '../context/ToastContext';
import { CheckCircle, AlertCircle, Info, Trophy, X, Medal } from 'lucide-react';

export const ToastSystem: React.FC = () => {
  const { toasts, removeToast } = useToast();

  if (toasts.length === 0) return null;

  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[100] flex flex-col gap-2 w-full max-w-sm px-4 pointer-events-none">
      {toasts.map(toast => (
        <div 
          key={toast.id}
          className={`
            pointer-events-auto flex items-center justify-between p-4 rounded-xl shadow-2xl border backdrop-blur-md animate-pop
            ${toast.type === 'success' ? 'bg-green-900/90 border-green-700 text-white' : ''}
            ${toast.type === 'error' ? 'bg-red-900/90 border-red-700 text-white' : ''}
            ${toast.type === 'info' ? 'bg-neutral-900/90 border-neutral-700 text-white' : ''}
            ${toast.type === 'level-up' ? 'bg-yellow-900/90 border-yellow-600 text-white' : ''}
            ${toast.type === 'badge' ? 'bg-emerald-900/90 border-emerald-600 text-white' : ''}
          `}
        >
          <div className="flex items-center gap-3">
            {toast.type === 'success' && <CheckCircle className="text-green-400" size={20} />}
            {toast.type === 'error' && <AlertCircle className="text-red-400" size={20} />}
            {toast.type === 'info' && <Info className="text-blue-400" size={20} />}
            {toast.type === 'level-up' && <Trophy className="text-yellow-400 animate-bounce" size={24} />}
            {toast.type === 'badge' && <Medal className="text-emerald-400 animate-pulse" size={24} />}

            <p className="font-bold text-sm">{toast.message}</p>
          </div>
          <button onClick={() => removeToast(toast.id)} className="text-white/50 hover:text-white">
            <X size={16} />
          </button>
        </div>
      ))}
    </div>
  );
};
